import React, { useState, useRef, useEffect } from 'react';
import { Globe, Play, Square, Activity, ArrowLeft, BarChart2, AlertCircle, Zap, RefreshCw, LayoutDashboard } from 'lucide-react';
import { Translation } from '../utils/i18n/types';
import { Modal } from './ui/Modal';
import { measureLatency, LATENCY_REGIONS, LatencyResult, LatencyRegion } from '../services/detectors/globalLatency';
import { WorldMap } from './heatmap/WorldMap';
import { TraceGraph } from './heatmap/TraceGraph';
import { formatNumber } from '../utils/formatters';

interface NetworkHeatmapModalProps {
  onClose: () => void;
  t: Translation['heatmap'];
}

interface TraceStats {
    count: number;
    lossCount: number;
    min: number;
    max: number;
    avg: number;
    jitter: number;
    last: number | null;
}

export const NetworkHeatmapModal: React.FC<NetworkHeatmapModalProps> = ({ onClose, t }) => {
  // Global Map State
  const [isRunningMap, setIsRunningMap] = useState(false);
  const [results, setResults] = useState<Record<string, LatencyResult>>({});

  // Detail/Trace View State
  const [selectedRegion, setSelectedRegion] = useState<LatencyRegion | null>(null);
  const [traceData, setTraceData] = useState<(number | null)[]>([]); // null = timeout
  const [isRunningTrace, setIsRunningTrace] = useState(false);
  const [traceStats, setTraceStats] = useState<TraceStats>({
      count: 0,
      lossCount: 0,
      min: Infinity,
      max: 0,
      avg: 0,
      jitter: 0,
      last: 0
  });

  const abortControllerRef = useRef<AbortController | null>(null);
  const traceIntervalRef = useRef<number | null>(null);

  const handleClose = () => {
      stopTest();
      stopTrace();
      onClose();
  };

  const stopTest = () => {
      if (abortControllerRef.current) {
          abortControllerRef.current.abort();
      }
      setIsRunningMap(false);
  };

  const stopTrace = () => {
      if (traceIntervalRef.current) {
          window.clearTimeout(traceIntervalRef.current);
          traceIntervalRef.current = null;
      }
      setIsRunningTrace(false);
  };

  // --- Global Map Logic ---
  const runTest = async () => {
      if (isRunningMap) return;
      setIsRunningMap(true);
      setResults({});
      abortControllerRef.current = new AbortController();

      // Batch requests to avoid choking browser
      const batchSize = 3;
      const queue = [...LATENCY_REGIONS];

      while (queue.length > 0 && !abortControllerRef.current.signal.aborted) {
          const batch = queue.splice(0, batchSize);

          // Mark as pending
          setResults(prev => {
              const next = { ...prev };
              batch.forEach(r => next[r.id] = { id: r.id, latency: 0, status: 'pending' });
              return next;
          });

          await Promise.all(batch.map(async (region) => {
              try {
                  const latency = await measureLatency(region.url);
                  setResults(prev => ({
                      ...prev,
                      [region.id]: { id: region.id, latency, status: 'success' }
                  }));
              } catch (e) {
                  setResults(prev => ({
                      ...prev,
                      [region.id]: { id: region.id, latency: 0, status: 'error' }
                  }));
              }
          }));

          // Small delay between batches
          await new Promise(r => setTimeout(r, 200));
      }

      setIsRunningMap(false);
  };

  // --- Trace Logic (Pseudo-MTR) ---
  const startTrace = () => {
      if (isRunningTrace || !selectedRegion) return;

      // Reset stats on start if trace data is empty or if restarting manually
      if (traceData.length === 0 || !isRunningTrace) {
          setTraceData(new Array(60).fill(0).map(() => 0)); 
          setTraceStats({ count: 0, lossCount: 0, min: Infinity, max: 0, avg: 0, jitter: 0, last: 0 });
      }

      setIsRunningTrace(true);

      const region = selectedRegion;

      const loop = async () => {
          const targetUrl = `${region.url}?t=${Date.now()}`;
          const start = performance.now();
          let latency: number | null = null;

          try {
              const controller = new AbortController();
              const timeoutId = setTimeout(() => controller.abort(), 2000);

              await fetch(targetUrl, { 
                  mode: 'no-cors', 
                  cache: 'no-store', 
                  method: 'HEAD',
                  signal: controller.signal
              });
              clearTimeout(timeoutId);
              const end = performance.now();
              latency = Math.round(end - start);
          } catch (e) {
              latency = null; // Timeout or error
          }

          // Update Data & Stats
          setTraceData(prev => [...prev.slice(1), latency]);

          setTraceStats(prev => {
              const newCount = prev.count + 1;
              const isLoss = latency === null;
              const newLossCount = prev.lossCount + (isLoss ? 1 : 0);

              if (isLoss) {
                  return { ...prev, count: newCount, lossCount: newLossCount };
              }

              const val = latency!;
              const newMin = Math.min(prev.min, val);
              const newMax = Math.max(prev.max, val);
              const newAvg = Math.round(prev.avg + (val - prev.avg) / (newCount - newLossCount));
              const newJitter = prev.last ? Math.abs(val - prev.last) : 0;
              const smoothJitter = Math.round(prev.jitter * 0.9 + newJitter * 0.1);

              return {
                  count: newCount,
                  lossCount: newLossCount,
                  min: newMin,
                  max: newMax,
                  avg: newAvg,
                  jitter: smoothJitter,
                  last: val
              };
          });

          if (traceIntervalRef.current) {
              traceIntervalRef.current = window.setTimeout(loop, 500);
          }
      };

      traceIntervalRef.current = window.setTimeout(loop, 0);
  };

  const handleStartTrace = () => {
      startTrace();
  };

  const handleStopTrace = () => {
      stopTrace();
  };

  // Reset when changing regions
  useEffect(() => {
      if (selectedRegion) {
          stopTrace(); 
          setTraceData(new Array(60).fill(0));
          setTraceStats({ count: 0, lossCount: 0, min: Infinity, max: 0, avg: 0, jitter: 0, last: 0 });
      } else {
          stopTrace();
      }
      return () => stopTrace();
  }, [selectedRegion]);


  // Helpers
  const getLatencyColor = (latency: number) => {
      if (latency === 0) return 'text-slate-400';
      if (latency < 100) return 'text-emerald-500';
      if (latency < 200) return 'text-yellow-500';
      return 'text-red-500';
  };

  const getRegionName = (id: string, defaultName: string) => {
      // @ts-ignore
      return t.regions?.[id] || defaultName;
  };

  const localizedRegions = LATENCY_REGIONS.map(r => ({
      ...r,
      name: getRegionName(r.id, r.name)
  }));

  return (
    <Modal
        title={selectedRegion ? t.mtr_title : t.title}
        icon={selectedRegion ? <Activity size={24} /> : <Globe size={24} />}
        onClose={handleClose}
        size="3xl"
        fullHeight
        noPadding
    >
        {/* Style injection for animations */}
        <style>{`
            @keyframes slideInRight {
                from { opacity: 0; transform: translateX(20px); }
                to { opacity: 1; transform: translateX(0); }
            }
            @keyframes slideInLeft {
                from { opacity: 0; transform: translateX(-20px); }
                to { opacity: 1; transform: translateX(0); }
            }
            .animate-slide-right { animation: slideInRight 0.3s ease-out forwards; }
            .animate-slide-left { animation: slideInLeft 0.3s ease-out forwards; }
        `}</style>

        <div className="flex flex-col h-full bg-slate-50 dark:bg-slate-900 relative overflow-hidden">

            {selectedRegion ? (
                // --- VIEW B: DETAILED TRACE (Full Overlay) ---
                <div className="flex flex-col h-full w-full absolute inset-0 bg-slate-50 dark:bg-slate-900 z-10 animate-slide-right">
                    {/* Header */}
                    <div className="p-4 border-b border-slate-200 dark:border-slate-700 bg-white dark:bg-slate-800 flex items-center justify-between shadow-sm z-20">
                        <button 
                            onClick={() => setSelectedRegion(null)}
                            className="flex items-center gap-2 px-3 py-1.5 rounded-lg text-sm font-medium text-slate-500 hover:text-slate-800 hover:bg-slate-100 dark:text-slate-400 dark:hover:text-white dark:hover:bg-slate-700 transition-colors"
                        >
                            <ArrowLeft size={16} />
                            {t.back}
                        </button>
                        <div className="flex items-center gap-3">
                            <span className="text-lg font-bold text-slate-800 dark:text-white">
                                {getRegionName(selectedRegion.id, selectedRegion.name)}
                            </span>
                            <div className="h-4 w-px bg-slate-300 dark:bg-slate-600 hidden sm:block" />
                            <span className="font-mono text-xs text-slate-400 hidden sm:block">{selectedRegion.url.split('/')[2]}</span>
                        </div>

                        {/* Prominent Controls */}
                        {!isRunningTrace ? (
                            <button 
                                onClick={handleStartTrace}
                                className="px-6 py-2 bg-emerald-600 hover:bg-emerald-700 text-white rounded-lg font-bold shadow-lg shadow-emerald-500/20 active:scale-95 transition-all flex items-center gap-2"
                            >
                                <Play size={16} fill="currentColor" />
                                {t.start}
                            </button>
                        ) : (
                            <button 
                                onClick={handleStopTrace}
                                className="px-6 py-2 bg-red-600 hover:bg-red-700 text-white rounded-lg font-bold shadow-lg shadow-red-500/20 active:scale-95 transition-all flex items-center gap-2 animate-pulse"
                            >
                                <Square size={16} fill="currentColor" />
                                {t.stop}
                            </button>
                        )}
                    </div>

                    {/* Main Graph Area */}
                    <div className="flex-1 p-6 bg-slate-900 relative overflow-hidden flex flex-col items-center justify-center min-h-0">
                        <div className={`absolute inset-0 transition-opacity duration-500 ${isRunningTrace ? 'opacity-80' : 'opacity-30 blur-sm'}`}>
                            <TraceGraph data={traceData} height={300} />
                        </div>

                        {/* Overlay for Idle State */}
                        {!isRunningTrace && traceStats.count === 0 && (
                            <div className="absolute inset-0 flex items-center justify-center bg-black/20 z-10">
                                <button 
                                    onClick={handleStartTrace}
                                    className="group relative flex flex-col items-center justify-center w-32 h-32 rounded-full bg-emerald-600/90 text-white shadow-2xl hover:scale-105 hover:bg-emerald-500 transition-all cursor-pointer backdrop-blur-sm border-4 border-white/10"
                                >
                                    <Zap size={40} className="mb-2 fill-white" />
                                    <span className="text-sm font-bold uppercase tracking-widest">{t.start}</span>
                                    <div className="absolute inset-0 rounded-full border-2 border-emerald-400/50 animate-ping pointer-events-none"></div>
                                </button>
                            </div>
                        )}

                        {/* Center Metric (Only show if we have data) */}
                        {traceStats.count > 0 && (
                            <div className="relative z-10 text-center mix-blend-difference">
                                <div className="text-6xl font-black text-white tabular-nums tracking-tighter">
                                    {traceStats.last ?? '--'}
                                </div>
                                <div className="text-sm font-bold text-indigo-400 uppercase tracking-widest mt-1">ms {t.current}</div>
                            </div>
                        )}
                    </div>

                    {/* Stats Grid */}
                    <div className="grid grid-cols-4 border-t border-slate-200 dark:border-slate-700 bg-white dark:bg-slate-800 shrink-0">
                        <div className="p-4 border-r border-slate-100 dark:border-slate-700 text-center">
                            <div className="text-[10px] text-slate-400 uppercase font-bold tracking-wider mb-1">{t.packet_loss}</div>
                            <div className={`text-xl font-bold tabular-nums ${traceStats.lossCount > 0 ? 'text-red-500' : 'text-emerald-500'}`}>
                                {traceStats.count > 0 ? ((traceStats.lossCount / traceStats.count) * 100).toFixed(1) : 0}%
                            </div>
                        </div>
                        <div className="p-4 border-r border-slate-100 dark:border-slate-700 text-center">
                            <div className="text-[10px] text-slate-400 uppercase font-bold tracking-wider mb-1">{t.jitter}</div>
                            <div className={`text-xl font-bold tabular-nums ${traceStats.jitter > 10 ? 'text-amber-500' : 'text-slate-700 dark:text-slate-200'}`}>
                                {traceStats.jitter} ms
                            </div>
                        </div>
                        <div className="p-4 border-r border-slate-100 dark:border-slate-700 text-center">
                            <div className="text-[10px] text-slate-400 uppercase font-bold tracking-wider mb-1">{t.avg_latency}</div>
                            <div className="text-xl font-bold text-slate-700 dark:text-slate-200 tabular-nums">
                                {traceStats.avg} ms
                            </div>
                        </div>
                        <div className="p-4 text-center">
                            <div className="text-[10px] text-slate-400 uppercase font-bold tracking-wider mb-1">{t.samples}</div>
                            <div className="text-xl font-bold text-slate-700 dark:text-slate-200 tabular-nums">
                                {traceStats.count}
                            </div>
                        </div>
                    </div>
                </div>
            ) : (
                // --- VIEW A: MAP & LIST (Dashboard Layout) ---
                <div className="flex flex-col lg:flex-row h-full w-full absolute inset-0 bg-slate-50 dark:bg-slate-900 z-0 animate-slide-left">

                    {/* Left/Top: Map Area */}
                    <div className="relative shrink-0 lg:flex-1 bg-slate-100 dark:bg-black/20 flex flex-col justify-center overflow-hidden border-b lg:border-b-0 lg:border-r border-slate-200 dark:border-slate-700 min-h-[300px] lg:min-h-0">
                        <div className="w-full h-full p-6 flex items-center justify-center">
                             {/* Map Container */}
                             <div className="w-full max-w-5xl h-full">
                                <WorldMap 
                                    regions={localizedRegions} 
                                    results={results} 
                                    onRegionSelect={setSelectedRegion} 
                                />
                             </div>
                        </div>

                        {/* Overlay Controls */}
                        <div className="absolute bottom-6 left-0 right-0 flex justify-center pointer-events-none z-10">
                             <button 
                                onClick={isRunningMap ? stopTest : runTest}
                                className={`
                                    pointer-events-auto px-8 py-3 rounded-full font-bold text-white shadow-xl flex items-center gap-2 active:scale-95 transition-all border border-white/10 backdrop-blur-sm
                                    ${isRunningMap 
                                        ? 'bg-red-600/90 hover:bg-red-700' 
                                        : 'bg-indigo-600/90 hover:bg-indigo-700'}
                                `}
                            >
                                {isRunningMap ? (
                                    <>
                                        <Square size={18} fill="currentColor" />
                                        {t.stop}
                                    </>
                                ) : (
                                    <>
                                        <Play size={18} fill="currentColor" />
                                        {t.start}
                                    </>
                                )}
                            </button>
                        </div>
                    </div>

                    {/* Right/Bottom: List Area */}
                    <div className="flex-1 lg:w-[400px] xl:w-[450px] lg:flex-none bg-white dark:bg-slate-800 flex flex-col min-h-0 shadow-xl z-20 relative">
                        <div className="p-4 border-b border-slate-100 dark:border-slate-700 bg-slate-50/80 dark:bg-slate-900/50 shrink-0 flex justify-between items-center backdrop-blur-sm">
                             <div className="flex items-center gap-2">
                                <LayoutDashboard size={16} className="text-slate-400" />
                                <h3 className="font-bold text-xs uppercase text-slate-500 tracking-wider">Regional Nodes</h3>
                             </div>
                             <div className="text-xs text-slate-400 font-mono">
                                 {localizedRegions.length} nodes
                             </div>
                        </div>

                        <div className="flex-1 overflow-y-auto p-4 custom-scrollbar min-h-0 bg-slate-50/30 dark:bg-transparent">
                             {/* Responsive Grid: 1 col on mobile, 2 cols on wide list (tablet mode), back to 1 col on desktop sidebar, 2 cols on very wide desktop */}
                             <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-1 xl:grid-cols-1 2xl:grid-cols-2 gap-3">
                                {LATENCY_REGIONS.map((region) => {
                                    const res = results[region.id];
                                    return (
                                        <div 
                                            key={region.id} 
                                            onClick={() => setSelectedRegion(region)}
                                            className="bg-white dark:bg-slate-800 p-3 rounded-lg border border-slate-200 dark:border-slate-700 flex justify-between items-center shadow-sm cursor-pointer hover:border-indigo-400 dark:hover:border-indigo-500 transition-all hover:shadow-md group"
                                        >
                                            <div className="flex flex-col min-w-0">
                                                <span className="font-bold text-slate-700 dark:text-slate-200 text-sm group-hover:text-indigo-600 dark:group-hover:text-indigo-400 transition-colors truncate pr-2">
                                                    {getRegionName(region.id, region.name)}
                                                </span>
                                                <span className="text-[10px] text-slate-400 font-mono">{region.url.split('/')[2]}</span>
                                            </div>
                                            <div className="text-right flex items-center gap-3 shrink-0">
                                                {res ? (
                                                    res.status === 'pending' ? (
                                                        <Activity size={16} className="text-indigo-500 animate-pulse" />
                                                    ) : res.status === 'error' ? (
                                                        <span className="text-xs font-bold text-red-400 bg-red-50 dark:bg-red-900/20 px-2 py-0.5 rounded">{t.status_error}</span>
                                                    ) : (
                                                        <span className={`text-sm font-mono font-bold ${getLatencyColor(res.latency)}`}>
                                                            {res.latency} <span className="text-[10px] font-normal text-slate-400">ms</span>
                                                        </span>
                                                    )
                                                ) : (
                                                    <span className="text-xs text-slate-300 dark:text-slate-600">-</span>
                                                )}
                                            </div>
                                        </div>
                                    );
                                })}
                             </div>
                        </div>
                    </div>
                </div>
            )}
        </div>
    </Modal>
  );
};

import React, { useState, useEffect } from 'react';
import { Globe, RefreshCw, Activity, Network, MapPin, Zap, Info, AlertCircle, Wifi, Copy, Check, Shield, Server, Radio, Monitor, Clock, Map as MapIcon, Home, Smartphone } from 'lucide-react';
import { Select } from './ui/Select';
import { Button } from './ui/Button';
import { Modal } from './ui/Modal';
import { 
    fetchIpInfoFromSource, 
    detectIpv6, 
    runWebRTCScan, 
    detectDns, 
    detectProtocols, 
    IpInfo, 
    WebRTCCandidate 
} from '../services/detectors/networkDiagnostics';

interface NetworkToolsModalProps {
    onClose: () => void;
    t: any;
    enableUdp?: boolean;
}

interface CDNStatus {
    name: string;
    url: string;
    status: 'idle' | 'loading' | 'success' | 'error';
    latency: number;
}

const IPV4_SOURCES = [
    { id: 'ippure', label: 'my.ippure.com (Detailed)' },
    { id: 'ipwhois', label: 'ipwho.is (Detailed)' },
    { id: 'ipapi', label: 'ipapi.co (Detailed)' },
    { id: 'cloudflare', label: 'Cloudflare (Simple)' },
    { id: 'ipify', label: 'ipify (Simple)' },
];

const IPV6_SOURCES = [
    { id: 'ipify', label: 'ipify (Global)' },
    { id: 'seeip', label: 'seeip.org' },
    { id: 'icanhazip', label: 'icanhazip' },
];

export const NetworkToolsModal: React.FC<NetworkToolsModalProps> = ({ onClose, t, enableUdp = false }) => {
    const networkT = t.settings.network;

    // IPv4 State
    const [ipInfo, setIpInfo] = useState<IpInfo | null>(null);
    const [loadingIp, setLoadingIp] = useState(false);
    const [activeIpv4Source, setActiveIpv4Source] = useState(() => localStorage.getItem('ipv4_source') || 'ippure');
    const [ipv4Copied, setIpv4Copied] = useState(false);

    // IPv6 State
    const [ipv6Address, setIpv6Address] = useState<string | null>(null);
    const [checkingIpv6, setCheckingIpv6] = useState(false);
    const [activeIpv6Source, setActiveIpv6Source] = useState(() => localStorage.getItem('ipv6_source') || 'ipify');
    const [ipv6Copied, setIpv6Copied] = useState(false);

    // Connectivity State
    const [testUrl, setTestUrl] = useState('');
    const [testResult, setTestResult] = useState<{status: string, latency?: number, code?: number} | null>(null);
    const [testingConn, setTestingConn] = useState(false);

    // Advanced Diagnostics State
    const [webrtcCandidates, setWebrtcCandidates] = useState<WebRTCCandidate[]>([]);
    const [scanningWebrtc, setScanningWebrtc] = useState(false);

    const [dnsInfo, setDnsInfo] = useState<{ip: string, geo: string} | null>(null);
    const [checkingDns, setCheckingDns] = useState(false);
    const [dnsError, setDnsError] = useState<string | null>(null);

    const [protocols, setProtocols] = useState<{h2: string, h3: string} | null>(null);
    const [checkingProto, setCheckingProto] = useState(false);

    // CDN State
    const [cdns, setCdns] = useState<CDNStatus[]>([
        { name: 'Tailwind CSS', url: 'https://cdn.tailwindcss.com', status: 'idle', latency: 0 },
        { name: 'Lucide Icons', url: 'https://esm.sh/lucide-react@0.263.1', status: 'idle', latency: 0 },
        { name: 'React', url: 'https://esm.sh/react@18.2.0', status: 'idle', latency: 0 },
        { name: 'FingerprintJS', url: 'https://esm.sh/@fingerprintjs/fingerprintjs@4.5.1', status: 'idle', latency: 0 }
    ]);

    useEffect(() => { localStorage.setItem('ipv4_source', activeIpv4Source); }, [activeIpv4Source]);
    useEffect(() => { localStorage.setItem('ipv6_source', activeIpv6Source); }, [activeIpv6Source]);

    const handleFetchIp = async () => {
        setLoadingIp(true);
        setIpInfo(null);
        const data = await fetchIpInfoFromSource(activeIpv4Source, enableUdp);
        setIpInfo(data);
        setLoadingIp(false);
    };

    const handleCheckIpv6 = async () => {
        setCheckingIpv6(true);
        setIpv6Address(null);
        const ip = await detectIpv6(activeIpv6Source, enableUdp);
        setIpv6Address(ip);
        setCheckingIpv6(false);
    };

    const handleCopy = (text: string, setCopied: (val: boolean) => void) => {
        navigator.clipboard.writeText(text);
        setCopied(true);
        setTimeout(() => setCopied(false), 2000);
    };

    const checkCDN = async (index: number) => {
        const cdn = cdns[index];
        const newCdns = [...cdns];
        newCdns[index].status = 'loading';
        setCdns(newCdns);

        const start = performance.now();
        try {
            if (enableUdp) {
                const res = await fetch('/api/proxy', {
                    method: 'POST',
                    headers: { 'Content-Type': 'application/json' },
                    body: JSON.stringify({ url: cdn.url, method: 'HEAD', useUdp: true })
                });
                if (!res.ok) throw new Error("Failed");
            } else {
                await fetch(cdn.url, { method: 'HEAD', cache: 'no-store', mode: 'no-cors' });
            }
            const end = performance.now();
            newCdns[index].status = 'success';
            newCdns[index].latency = Math.round(end - start);
        } catch (e) {
            newCdns[index].status = 'error';
        }
        setCdns([...newCdns]);
    };

    const checkAllCDNs = () => {
        cdns.forEach((_, idx) => checkCDN(idx));
    };

    const runConnectivityTest = async () => {
        if (!testUrl) return;
        setTestingConn(true);
        setTestResult(null);

        let urlToTest = testUrl;
        if (!/^https?:\/\//i.test(urlToTest)) {
            urlToTest = 'https://' + urlToTest;
        }

        const start = performance.now();
        try {
            if (enableUdp) {
                const res = await fetch('/api/proxy', {
                    method: 'POST',
                    headers: { 'Content-Type': 'application/json' },
                    body: JSON.stringify({ url: urlToTest, method: 'HEAD', useUdp: true })
                });
                if (!res.ok) throw new Error("Proxy error");
            } else {
                await fetch(urlToTest, { method: 'HEAD', mode: 'no-cors', cache: 'no-store' });
            }
            const end = performance.now();
            setTestResult({
                status: 'Success',
                latency: Math.round(end - start),
                code: 200
            });
        } catch (e) {
            setTestResult({ status: 'Failed (Network Error)' });
        }
        setTestingConn(false);
    };

    const handleWebRTC = async () => {
        setScanningWebrtc(true);
        setWebrtcCandidates([]);
        await runWebRTCScan((candidate) => {
            setWebrtcCandidates(prev => {
                if (prev.some(x => x.ip === candidate.ip && x.port === candidate.port)) return prev;
                return [...prev, candidate];
            });
        });
        setScanningWebrtc(false);
    };

    const handleDnsCheck = async () => {
        setCheckingDns(true);
        setDnsInfo(null);
        setDnsError(null);
        try {
            const info = await detectDns(enableUdp);
            if (info) setDnsInfo(info);
            else throw new Error('Unknown');
        } catch (e) {
            setDnsError("Failed to detect resolver (Likely blocked by AdBlock or CORS)");
        }
        setCheckingDns(false);
    };

    const handleProtoCheck = async () => {
        setCheckingProto(true);
        setProtocols(null);
        const res = await detectProtocols();
        setProtocols(res);
        setCheckingProto(false);
    };

    const renderBentoItem = (icon: any, label: string, value: string | number | undefined | null | boolean, colorClass = 'text-slate-800 dark:text-slate-200', colSpan = 'col-span-1') => {
        if (value === undefined || value === null || value === '') return null;

        const displayValue = typeof value === 'boolean' ? (value ? networkT.ip.yes : networkT.ip.no) : value;

        return (
            <div className={`flex flex-col gap-1.5 p-3.5 bg-slate-50 dark:bg-slate-900/40 border border-slate-100 dark:border-slate-800/60 rounded-xl hover:bg-slate-100 dark:hover:bg-slate-800/80 transition-colors ${colSpan}`}>
                <div className="flex items-center gap-2 text-slate-500 dark:text-slate-400">
                    {React.createElement(icon, { size: 14, className: "opacity-70" })}
                    <span className="text-xs font-semibold uppercase tracking-wider">{label}</span>
                </div>
                <div className={`text-sm font-medium break-words ${colorClass}`}>
                    {displayValue}
                </div>
            </div>
        );
    };

    return (
        <Modal 
            onClose={onClose} 
            title={t.settings.nav.network || "Network Tools"} 
            icon={<Wifi size={24} className="text-indigo-500" />}
            size="4xl"
            fullHeight
        >
            <div className="max-w-5xl mx-auto space-y-6">

                {/* Modern IP Configuration Card */}
                <div className="bg-white dark:bg-slate-800/60 rounded-2xl border border-slate-200 dark:border-slate-700/60 shadow-sm overflow-hidden">
                    <div className="px-6 py-5 border-b border-slate-100 dark:border-slate-700/60 flex items-center justify-between bg-slate-50/50 dark:bg-slate-800/30">
                        <div className="flex items-center gap-3">
                            <div className="p-2 bg-indigo-50 dark:bg-indigo-500/10 rounded-lg text-indigo-500 dark:text-indigo-400">
                                <Globe size={20} />
                            </div>
                            <h3 className="font-semibold text-slate-800 dark:text-slate-200">{networkT.ip.title}</h3>
                        </div>
                    </div>

                    <div className="p-6 md:p-8 space-y-8">
                        {/* IPv4 Fetch Block */}
                        <div className="flex flex-col lg:flex-row lg:items-start justify-between gap-6">
                            <div className="space-y-4 flex-1">
                                <div className="flex items-center gap-3">
                                    <span className="px-2.5 py-1 text-xs font-bold text-indigo-600 bg-indigo-50 dark:bg-indigo-500/20 dark:text-indigo-300 rounded-md ring-1 ring-inset ring-indigo-500/20">{networkT.ip.ipv4}</span>
                                    <Select 
                                        value={activeIpv4Source}
                                        options={IPV4_SOURCES}
                                        onChange={setActiveIpv4Source}
                                        size="sm"
                                        fullWidth={false}
                                        className="w-[200px]"
                                    />
                                    <Button 
                                        onClick={handleFetchIp}
                                        isLoading={loadingIp}
                                        variant="secondary"
                                        size="sm"
                                        leftIcon={<RefreshCw size={14} />}
                                    >
                                        {networkT.ip.fetch}
                                    </Button>
                                </div>

                                {ipInfo?.error && (
                                    <div className="text-sm text-red-500 flex items-center gap-2 bg-red-50 dark:bg-red-900/10 p-3 rounded-lg border border-red-100 dark:border-red-900/30">
                                        <AlertCircle size={16} />
                                        <span>{ipInfo.error}</span>
                                    </div>
                                )}

                                {ipInfo && !ipInfo.error && (
                                    <div className="animate-in fade-in slide-in-from-bottom-2 duration-300 space-y-4">
                                        <div className="flex items-center gap-4 border border-slate-200 dark:border-slate-700/60 rounded-xl p-4 bg-slate-50 dark:bg-slate-900/40">
                                            <div className="font-mono text-3xl md:text-5xl font-extrabold text-slate-800 dark:text-white tracking-tighter break-all bg-clip-text text-transparent bg-gradient-to-r from-slate-800 to-slate-500 dark:from-white dark:to-slate-400">
                                                {ipInfo.ip}
                                            </div>
                                            <button
                                                onClick={() => handleCopy(ipInfo.ip!, setIpv4Copied)}
                                                className="p-2.5 rounded-xl bg-white dark:bg-slate-800 text-slate-400 hover:text-indigo-600 hover:bg-indigo-50 dark:hover:text-indigo-400 dark:hover:bg-indigo-500/20 ring-1 ring-slate-200 dark:ring-slate-700 shadow-sm transition-all active:scale-95"
                                            >
                                                {ipv4Copied ? <Check size={20} className="text-emerald-500" /> : <Copy size={20} />}
                                            </button>
                                        </div>

                                        {/* Bento Grid layout for IP details */}
                                        <div className="grid grid-cols-2 md:grid-cols-3 lg:grid-cols-4 gap-3">
                                            {renderBentoItem(MapPin, networkT.ip.detail_location, [ipInfo.city, ipInfo.region, ipInfo.countryCode || ipInfo.country].filter(Boolean).join(', '), 'text-slate-800 dark:text-slate-200', 'col-span-2')}
                                            {renderBentoItem(Network, "ISP", ipInfo.isp, 'font-medium font-sans', 'col-span-2')}
                                            {renderBentoItem(Server, networkT.ip.detail_asn, ipInfo.asn ? `AS${ipInfo.asn}` : undefined)}
                                            {renderBentoItem(Clock, networkT.ip.detail_timezone, ipInfo.timezone, "font-mono text-xs")}
                                            {renderBentoItem(MapIcon, networkT.ip.detail_zip, ipInfo.postalCode)}
                                            {renderBentoItem(Shield, networkT.ip.detail_fraud, ipInfo.fraudScore, ipInfo.fraudScore !== undefined ? (ipInfo.fraudScore > 50 ? 'text-red-500 font-bold' : 'text-emerald-500 font-bold') : undefined)}
                                            {renderBentoItem(Home, networkT.ip.detail_residential, ipInfo.isResidential, ipInfo.isResidential ? 'text-emerald-600 dark:text-emerald-400' : 'text-slate-500')}
                                            {renderBentoItem(Radio, networkT.ip.detail_broadcast, ipInfo.isBroadcast)}
                                            {renderBentoItem(Smartphone, networkT.ip.detail_ua, ipInfo.userAgent, 'text-xs text-slate-500 line-clamp-2', 'col-span-2 md:col-span-3 lg:col-span-4')}
                                        </div>
                                    </div>
                                )}
                            </div>

                            {/* Separator for Desktop/Mobile */}
                            <div className="w-full lg:w-px h-px lg:h-auto bg-slate-200 dark:bg-slate-700/60 self-stretch my-2 lg:my-0"></div>

                            {/* IPv6 Fetch Block */}
                            <div className="space-y-4 lg:w-1/3 flex-shrink-0">
                                <div className="flex items-center gap-3">
                                    <span className="px-2.5 py-1 text-xs font-bold text-purple-600 bg-purple-50 dark:bg-purple-500/20 dark:text-purple-300 rounded-md ring-1 ring-inset ring-purple-500/20">{networkT.ip.ipv6}</span>
                                    <Button 
                                        onClick={handleCheckIpv6}
                                        isLoading={checkingIpv6}
                                        variant="secondary"
                                        size="sm"
                                        leftIcon={<Zap size={14} />}
                                    >
                                        {networkT.ip.check_v6}
                                    </Button>
                                </div>
                                <Select 
                                    value={activeIpv6Source}
                                    options={IPV6_SOURCES}
                                    onChange={setActiveIpv6Source}
                                    size="sm"
                                    fullWidth={true}
                                />

                                {ipv6Address && ipv6Address !== 'fail' ? (
                                    <div className="p-4 bg-slate-50 dark:bg-slate-900/40 border border-slate-200 dark:border-slate-700/60 rounded-xl space-y-3">
                                        <div className="flex justify-between items-start gap-2">
                                            <div className="font-mono text-sm font-bold text-slate-800 dark:text-white break-all leading-tight">
                                                {ipv6Address}
                                            </div>
                                            <button
                                                onClick={() => handleCopy(ipv6Address!, setIpv6Copied)}
                                                className="p-1.5 rounded-lg text-slate-400 hover:text-purple-600 hover:bg-purple-50 dark:hover:bg-purple-500/20 transition-colors shrink-0"
                                            >
                                                {ipv6Copied ? <Check size={16} className="text-emerald-500" /> : <Copy size={16} />}
                                            </button>
                                        </div>
                                        <div className="flex items-center gap-2">
                                            <span className="relative flex h-2.5 w-2.5">
                                                <span className="animate-ping absolute inline-flex h-full w-full rounded-full bg-emerald-400 opacity-75"></span>
                                                <span className="relative inline-flex rounded-full h-2.5 w-2.5 bg-emerald-500"></span>
                                            </span>
                                            <span className="text-xs font-bold text-emerald-600 dark:text-emerald-400">{networkT.ip.success_v6}</span>
                                        </div>
                                    </div>
                                ) : ipv6Address === 'fail' ? (
                                    <div className="p-4 bg-slate-50 dark:bg-slate-900/40 border border-slate-200 dark:border-slate-700/60 rounded-xl flex items-center gap-2">
                                        <div className="w-2.5 h-2.5 rounded-full bg-slate-300 dark:bg-slate-600"></div>
                                        <span className="text-sm font-medium text-slate-500 dark:text-slate-400">{networkT.ip.fail_v6}</span>
                                    </div>
                                ) : (
                                    <div className="p-4 border border-dashed border-slate-200 dark:border-slate-700 rounded-xl flex items-center gap-2 text-slate-400 text-sm">
                                        <Info size={16} />
                                        IPv6 status pending detection...
                                    </div>
                                )}
                            </div>
                        </div>
                    </div>
                </div>

                {/* Diagnostics and Utils Grid */}
                <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
                    {/* Advanced Diagnostics Container */}
                    <div className="bg-white dark:bg-slate-800/60 rounded-2xl border border-slate-200 dark:border-slate-700/60 shadow-sm overflow-hidden flex flex-col">
                        <div className="px-6 py-4 border-b border-slate-100 dark:border-slate-700/60 flex items-center gap-3 bg-slate-50/50 dark:bg-slate-800/30">
                            <Server size={18} className="text-slate-500 text-indigo-500" />
                            <h3 className="font-semibold text-slate-800 dark:text-slate-200">{networkT.diagnostics.title}</h3>
                        </div>

                        <div className="p-6 space-y-6 flex-1 flex flex-col">
                            {/* WebRTC */}
                            <div>
                                <div className="flex items-center justify-between mb-3">
                                    <div className="flex items-center gap-2">
                                        <Radio size={16} className="text-blue-500" />
                                        <h4 className="text-sm font-bold text-slate-800 dark:text-slate-200">{networkT.diagnostics.webrtc.title}</h4>
                                    </div>
                                    <Button onClick={handleWebRTC} isLoading={scanningWebrtc} variant="secondary" size="xs">{networkT.diagnostics.webrtc.btn}</Button>
                                </div>
                                {webrtcCandidates.length > 0 ? (
                                    <div className="bg-slate-50 dark:bg-slate-900/40 rounded-xl border border-slate-200 dark:border-slate-700/60 overflow-hidden text-xs">
                                        <table className="w-full text-left">
                                            <thead className="bg-slate-100/50 dark:bg-slate-800/50 border-b border-slate-200 dark:border-slate-700/60 text-slate-500 dark:text-slate-400">
                                                <tr>
                                                    <th className="px-3 py-2 font-medium">{networkT.diagnostics.webrtc.columns.type}</th>
                                                    <th className="px-3 py-2 font-medium">{networkT.diagnostics.webrtc.columns.ip}</th>
                                                </tr>
                                            </thead>
                                            <tbody className="divide-y divide-slate-100 dark:divide-slate-700/60">
                                                {webrtcCandidates.map(c => (
                                                    <tr key={c.id}>
                                                        <td className="px-3 py-2">
