export class ParticleSystem {
    particles: Float32Array;
    count: number;
    width: number;
    height: number;

    constructor(count: number, width: number, height: number) {
        this.count = count;
        this.width = width;
        this.height = height;
        // x, y, vx, vy, life, speedOffset
        this.particles = new Float32Array(count * 6);
        this.init();
    }

    init() {
        for (let i = 0; i < this.count; i++) {
            this.resetParticle(i, true);
        }
    }

    resetParticle(i: number, randomStart = false) {
        const idx = i * 6;
        const angle = Math.random() * Math.PI * 2;
        // Start from center or random position
        const dist = randomStart ? Math.random() * Math.min(this.width, this.height) * 0.5 : 0;

        this.particles[idx] = this.width / 2 + Math.cos(angle) * dist;
        this.particles[idx + 1] = this.height / 2 + Math.sin(angle) * dist;

        // Base velocity outward
        const speed = Math.random() * 2 + 0.5;
        this.particles[idx + 2] = Math.cos(angle) * speed;
        this.particles[idx + 3] = Math.sin(angle) * speed;

        this.particles[idx + 4] = Math.random(); // Life (0-1)
        this.particles[idx + 5] = Math.random(); // Speed modifier
    }

    update(gflops: number, ctx: CanvasRenderingContext2D) {
        // Clear with trails
        ctx.fillStyle = 'rgba(0, 0, 0, 0.2)';
        ctx.fillRect(0, 0, this.width, this.height);

        // Intensity based on GFLOPS (0 to ~1000 range expected, map to 0-1 factor)
        const intensity = Math.min(gflops / 500, 2); 
        const speedMultiplier = 1 + intensity * 5;

        // Color mapping based on intensity: Blue -> Cyan -> White -> Orange -> Red
        let r = 0, g = 0, b = 0;
        if (intensity < 0.2) { r=50; g=100; b=255; } // Blue
        else if (intensity < 0.5) { r=0; g=255; b=255; } // Cyan
        else if (intensity < 0.8) { r=255; g=255; b=255; } // White
        else if (intensity < 1.2) { r=255; g=165; b=0; } // Orange
        else { r=255; g=50; b=50; } // Red

        ctx.fillStyle = `rgb(${r},${g},${b})`;

        for (let i = 0; i < this.count; i++) {
            const idx = i * 6;

            // Move
            this.particles[idx] += this.particles[idx + 2] * speedMultiplier * this.particles[idx + 5];
            this.particles[idx + 1] += this.particles[idx + 3] * speedMultiplier * this.particles[idx + 5];

            // Render
            const size = Math.max(1, intensity * 3 * this.particles[idx + 5]);
            ctx.fillRect(this.particles[idx], this.particles[idx + 1], size, size);

            // Reset if out of bounds
            if (
                this.particles[idx] < 0 || 
                this.particles[idx] > this.width || 
                this.particles[idx + 1] < 0 || 
                this.particles[idx + 1] > this.height
            ) {
                this.resetParticle(i);
            }
        }

        // Draw Center Core
        const coreSize = 10 + intensity * 40;
        const gradient = ctx.createRadialGradient(
            this.width/2, this.height/2, coreSize * 0.1, 
            this.width/2, this.height/2, coreSize
        );
        gradient.addColorStop(0, 'white');
        gradient.addColorStop(0.4, `rgba(${r},${g},${b},0.8)`);
        gradient.addColorStop(1, `rgba(${r},${g},${b},0)`);

        ctx.fillStyle = gradient;
        ctx.beginPath();
        ctx.arc(this.width/2, this.height/2, coreSize, 0, Math.PI * 2);
        ctx.fill();
    }
}

import React, { useState, useRef } from 'react';
import { MousePointer2, RefreshCw } from 'lucide-react';
import { Translation } from '../../utils/i18n/types';
import { formatNumber } from '../../utils/formatters';

interface MouseTabProps {
    t: Translation['hardwareToolsModal'];
}

export const MouseTab: React.FC<MouseTabProps> = ({ t }) => {
    const [mouseRate, setMouseRate] = useState(0);
    const [peakRate, setPeakRate] = useState(0);
    const mouseTimestamps = useRef<number[]>([]);
    const mouseRaf = useRef<number | null>(null);

    const handleMouseMove = (e: React.MouseEvent) => {
        const now = performance.now();
        mouseTimestamps.current.push(now);

        // Keep only last 1 second of samples
        const oneSecondAgo = now - 1000;
        mouseTimestamps.current = mouseTimestamps.current.filter(t => t > oneSecondAgo);

        // Calculate rate
        if (!mouseRaf.current) {
            mouseRaf.current = requestAnimationFrame(() => {
                const count = mouseTimestamps.current.length;
                setMouseRate(count);
                setPeakRate(prev => Math.max(prev, count));
                mouseRaf.current = null;
            });
        }
    };

    const resetMouseStats = () => {
        setMouseRate(0);
        setPeakRate(0);
        mouseTimestamps.current = [];
    };

    return (
        <div className="h-full flex flex-col animate-in fade-in duration-300">
            <div 
                onMouseMove={handleMouseMove}
                className="flex-1 bg-white dark:bg-slate-800 rounded-xl border-2 border-dashed border-slate-300 dark:border-slate-700 hover:border-indigo-400 dark:hover:border-indigo-600 transition-colors cursor-none flex flex-col items-center justify-center p-8 group relative overflow-hidden"
            >
                <div className="absolute inset-0 bg-indigo-50/50 dark:bg-indigo-900/10 opacity-0 group-hover:opacity-100 transition-opacity pointer-events-none" />

                <MousePointer2 size={32} className="text-indigo-300 dark:text-indigo-800 mb-4 opacity-50" />
                <p className="text-slate-400 text-sm text-center max-w-xs mb-8 pointer-events-none select-none">
                    {t.mouse_instruction}
                </p>

                <div className="grid grid-cols-2 gap-8 w-full max-w-md pointer-events-none select-none relative z-10">
                    <div className="text-center">
                        <div className="text-5xl font-bold text-indigo-600 dark:text-indigo-400 font-mono tabular-nums">{formatNumber(mouseRate)}</div>
                        <div className="text-xs font-bold text-slate-400 uppercase tracking-widest mt-2">{t.mouse_rate} (Hz)</div>
                    </div>
                    <div className="text-center">
                        <div className="text-5xl font-bold text-slate-700 dark:text-slate-300 font-mono tabular-nums">{formatNumber(peakRate)}</div>
                        <div className="text-xs font-bold text-slate-400 uppercase tracking-widest mt-2">{t.mouse_peak} (Hz)</div>
                    </div>
                </div>
            </div>
            <div className="flex justify-center mt-4">
                <button onClick={resetMouseStats} className="flex items-center gap-2 text-xs text-slate-500 hover:text-indigo-600 transition-colors">
                    <RefreshCw size={12} />
                    Reset Stats
                </button>
            </div>
        </div>
    );
};

import React, { useState, useEffect, useRef } from 'react';
import { Translation } from '../../utils/i18n/types';

interface TouchTabProps {
    t: Translation['hardwareToolsModal'];
}

export const TouchTab: React.FC<TouchTabProps> = ({ t }) => {
    const [touchCount, setTouchCount] = useState(0);
    const canvasRef = useRef<HTMLCanvasElement>(null);

    useEffect(() => {
        const canvas = canvasRef.current;
        if (!canvas) return;

        const ctx = canvas.getContext('2d');
        if (!ctx) return;

        const resize = () => {
            canvas.width = canvas.offsetWidth;
            canvas.height = canvas.offsetHeight;
        };
        resize();
        window.addEventListener('resize', resize);

        const touches = new Map<number, {x: number, y: number, color: string}>();
        const colors = ['#EF4444', '#3B82F6', '#10B981', '#F59E0B', '#8B5CF6'];

        const draw = () => {
            ctx.clearRect(0, 0, canvas.width, canvas.height);

            // Instruction bg
            ctx.font = "14px Inter";
            ctx.fillStyle = "#64748b";
            ctx.textAlign = "center";
            if (touches.size === 0) {
                ctx.fillText(t.touch_instruction, canvas.width/2, canvas.height/2);
            }

            touches.forEach((t, id) => {
                ctx.beginPath();
                ctx.arc(t.x, t.y, 40, 0, Math.PI * 2);
                ctx.fillStyle = t.color;
                ctx.fill();
                ctx.strokeStyle = "white";
                ctx.lineWidth = 3;
                ctx.stroke();
            });

            requestAnimationFrame(draw);
        };

        const updateTouch = (e: TouchEvent) => {
            e.preventDefault();
            touches.clear();
            for (let i=0; i<e.touches.length; i++) {
                const t = e.touches[i];
                const rect = canvas.getBoundingClientRect();
                touches.set(t.identifier, {
                    x: t.clientX - rect.left,
                    y: t.clientY - rect.top,
                    color: colors[i % colors.length]
                });
            }
            setTouchCount(e.touches.length);
        };

        canvas.addEventListener('touchstart', updateTouch, {passive: false});
        canvas.addEventListener('touchmove', updateTouch, {passive: false});
        canvas.addEventListener('touchend', updateTouch, {passive: false});
        canvas.addEventListener('touchcancel', updateTouch, {passive: false});

        const anim = requestAnimationFrame(draw);

        return () => {
            window.removeEventListener('resize', resize);
            cancelAnimationFrame(anim);
        };
    }, [t.touch_instruction]);

    return (
        <div className="h-full flex flex-col animate-in fade-in duration-300">
            <div className="bg-slate-900 rounded-xl overflow-hidden flex-1 relative shadow-inner border-2 border-slate-200 dark:border-slate-700 cursor-crosshair touch-none">
                <canvas ref={canvasRef} className="w-full h-full block" />
                <div className="absolute top-4 right-4 bg-black/50 backdrop-blur px-3 py-1 rounded-full text-white text-xs font-mono pointer-events-none select-none">
                    {t.touch_count}: {touchCount}
                </div>
            </div>
        </div>
    );
};

import React, { useState, useEffect } from 'react';
import { Film, Battery, Zap, Check, X, MonitorPlay, Music, Speaker, Tv, Filter } from 'lucide-react';
import { Translation } from '../../utils/i18n/types';
import { videoCodecs, videoResolutions, audioCodecs, audioConfigs } from '../../data/codecs';

interface VideoTabProps {
    t: Translation['hardwareToolsModal'];
    values: Translation['values'];
    labels: Translation['labels'];
}

export const VideoTab: React.FC<VideoTabProps> = ({ t, values, labels }) => {
    const [videoResults, setVideoResults] = useState<any[]>([]);
    const [audioResults, setAudioResults] = useState<any[]>([]);
    const [progress, setProgress] = useState(0);
    const [isTesting, setIsTesting] = useState(false);
    const [showSupportedOnly, setShowSupportedOnly] = useState(false);

    useEffect(() => {
        const runTests = async () => {
            setIsTesting(true);
            const tempVideoResults: any[] = [];
            const tempAudioResults: any[] = [];

            let done = 0;
            const total = (videoCodecs.length * videoResolutions.length) + (audioCodecs.length * audioConfigs.length);

            // --- Run Video Tests ---
            for (const codec of videoCodecs) {
                const row = { 
                    codec: codec.name, 
                    profile: codec.profile, 
                    bitDepth: codec.bitDepth,
                    tag: codec.tag, 
                    tests: [] as any[] 
                };

                const resPromises = videoResolutions.map(async (res) => {
                    try {
                        // @ts-ignore
                        if (navigator.mediaCapabilities) {
                            const config: any = {
                                type: 'file', 
                                video: {
                                    contentType: codec.type,
                                    width: res.width,
                                    height: res.height,
                                    bitrate: res.bitrate,
                                    framerate: res.fps,
                                }
                            };

                            // Add HDR config if present
                            if ((codec as any).hdrConfig) {
                                Object.assign(config.video, (codec as any).hdrConfig);
                            }

                            // @ts-ignore
                            const info = await navigator.mediaCapabilities.decodingInfo(config);
                            return {
                                ...res,
                                supported: info.supported,
                                smooth: info.smooth,
                                efficient: info.powerEfficient
                            };
                        } else {
                            return { ...res, error: 'API N/A' };
                        }
                    } catch (e) {
                        return { ...res, supported: false };
                    }
                });

                const resResults = await Promise.all(resPromises);
                row.tests = resResults;
                tempVideoResults.push(row);

                done += videoResolutions.length;
                setProgress(Math.round((done / total) * 100));
                setVideoResults([...tempVideoResults]);
            }

            // --- Run Audio Tests ---
            for (const codec of audioCodecs) {
                const row = {
                    codec: codec.name,
                    label: codec.label,
                    tag: codec.tag,
                    tests: [] as any[]
                };

                const audioPromises = audioConfigs.map(async (conf) => {
                    try {
                        // @ts-ignore
                        if (navigator.mediaCapabilities) {
                            const config = {
                                type: 'file',
                                audio: {
                                    contentType: codec.type,
                                    channels: conf.channels,
                                    bitrate: conf.bitrate,
                                    samplerate: conf.samplerate
                                }
                            };
                            // @ts-ignore
                            const info = await navigator.mediaCapabilities.decodingInfo(config);
                            return {
                                ...conf,
                                supported: info.supported,
                                smooth: info.smooth,
                                efficient: info.powerEfficient
                            };
                        } else {
                            return { ...conf, error: 'API N/A' };
                        }
                    } catch (e) {
                        return { ...conf, supported: false };
                    }
                });

                const audResults = await Promise.all(audioPromises);
                row.tests = audResults;
                tempAudioResults.push(row);

                done += audioConfigs.length;
                setProgress(Math.round((done / total) * 100));
                setAudioResults([...tempAudioResults]);
            }

            setIsTesting(false);
        };

        runTests();
    }, []);

    const getTagColor = (tag: string) => {
        switch(tag) {
            case 'HDR10': return 'bg-amber-100 text-amber-700 dark:bg-amber-900/30 dark:text-amber-400 border-amber-200 dark:border-amber-800/50';
            case 'HLG': return 'bg-orange-100 text-orange-700 dark:bg-orange-900/30 dark:text-orange-400 border-orange-200 dark:border-orange-800/50';
            case 'Dolby': return 'bg-indigo-100 text-indigo-700 dark:bg-indigo-900/30 dark:text-indigo-400 border-indigo-200 dark:border-indigo-800/50';
            case 'DTS': return 'bg-red-100 text-red-700 dark:bg-red-900/30 dark:text-red-400 border-red-200 dark:border-red-800/50';
            case 'Hi-Res': return 'bg-emerald-100 text-emerald-700 dark:bg-emerald-900/30 dark:text-emerald-400 border-emerald-200 dark:border-emerald-800/50';
            case 'SDR': return 'bg-slate-100 text-slate-600 dark:bg-slate-800 dark:text-slate-400 border-slate-200 dark:border-slate-700';
            default: return 'bg-slate-100 text-slate-600 dark:bg-slate-700 dark:text-slate-400';
        }
    };

    const getFilteredResults = (results: any[]) => {
        if (!showSupportedOnly) return results;
        return results.map(row => ({
            ...row,
            tests: row.tests.filter((t: any) => t.supported)
        })).filter(row => row.tests.length > 0);
    };

    const filteredVideo = getFilteredResults(videoResults);
    const filteredAudio = getFilteredResults(audioResults);

    return (
        <div className="h-full overflow-y-auto animate-in fade-in duration-300 custom-scrollbar pb-4">
            <div className="mb-6 flex items-center justify-between sticky top-0 bg-slate-50 dark:bg-slate-900 z-10 py-3 border-b border-slate-200 dark:border-slate-800">
                <div className="flex items-center gap-2 text-sm text-slate-500">
                    <MonitorPlay size={16} />
                    {isTesting ? t.video_instruction : t.tab_video}
                </div>
                {isTesting ? (
                    <div className="flex items-center gap-2">
                        <div className="w-24 h-1.5 bg-slate-200 dark:bg-slate-700 rounded-full overflow-hidden">
                            <div className="h-full bg-indigo-500 transition-all duration-300" style={{ width: `${progress}%` }} />
                        </div>
                        <span className="text-xs font-mono text-indigo-600 dark:text-indigo-400">{progress}%</span>
                    </div>
                ) : (
                    <div className="flex items-center gap-3">
                        <button 
                            onClick={() => setShowSupportedOnly(!showSupportedOnly)}
                            className={`text-xs font-medium px-2 py-1 rounded border transition-colors flex items-center gap-1 ${showSupportedOnly ? 'bg-indigo-50 border-indigo-200 text-indigo-700 dark:bg-indigo-900/30 dark:border-indigo-800 dark:text-indigo-400' : 'bg-white border-slate-200 text-slate-600 dark:bg-slate-800 dark:border-slate-700 dark:text-slate-400'}`}
                        >
                            <Filter size={12} />
                            {t.filter_supported}
                        </button>
                        <span className="text-xs font-bold text-emerald-500 flex items-center gap-1">
                            <Check size={14} /> Done
                        </span>
                    </div>
                )}
            </div>

            {/* Video Section */}
            {filteredVideo.length > 0 && (
                <div className="mb-8">
                    <h3 className="text-xs font-bold text-slate-400 uppercase tracking-wider mb-3 flex items-center gap-2 px-1">
                        <Film size={14} />
                        {labels.video_codecs}
                    </h3>
                    <div className="space-y-3">
                        {filteredVideo.map((row, rIdx) => (
                            <div key={rIdx} className="bg-white dark:bg-slate-800 rounded-xl border border-slate-200 dark:border-slate-700 overflow-hidden shadow-sm">
                                <div className="bg-slate-50 dark:bg-slate-900/50 px-4 py-2 border-b border-slate-100 dark:border-slate-700 flex items-center justify-between">
                                    <div className="flex items-center gap-2 overflow-hidden">
                                        <h3 className="font-bold text-sm text-slate-800 dark:text-slate-100 whitespace-nowrap">{row.codec}</h3>
                                        <span className="text-xs text-slate-500 dark:text-slate-400 ml-1 truncate">({row.profile})</span>
                                    </div>
                                    <div className="flex gap-1.5">
                                        <span className={`text-[10px] font-bold px-1.5 py-0.5 rounded border ${row.bitDepth === 10 ? 'bg-purple-100 text-purple-700 border-purple-200 dark:bg-purple-900/30 dark:text-purple-400 dark:border-purple-800/50' : 'bg-slate-100 text-slate-600 border-slate-200 dark:bg-slate-800 dark:text-slate-400 dark:border-slate-700'}`}>
                                            {row.bitDepth}-bit
                                        </span>
                                        <span className={`flex items-center gap-1 text-[10px] font-bold px-1.5 py-0.5 rounded border ${getTagColor(row.tag)}`}>
                                            {row.tag === 'Dolby' ? 'Vision' : row.tag}
                                        </span>
                                    </div>
                                </div>

                                <div className="grid grid-cols-3 divide-x divide-slate-100 dark:divide-slate-700">
                                    {row.tests.map((test: any, idx: number) => (
                                        <div key={idx} className={`p-3 flex flex-col gap-1.5 items-center justify-center text-center transition-colors ${test.supported ? '' : 'bg-slate-50/50 dark:bg-slate-800/30 opacity-60'}`}>
                                            <span className="text-[10px] font-bold text-slate-500 uppercase tracking-wide">{test.label}</span>

                                            {test.error ? (
                                                <span className="text-xs text-red-400">API Error</span>
                                            ) : !test.supported ? (
                                                <span className="text-xs font-bold text-slate-300 dark:text-slate-600">{values.not_supported}</span>
                                            ) : (
                                                <div className="flex gap-2">
                                                    <div 
                                                        className={`flex items-center gap-1 px-1.5 py-0.5 rounded ${test.efficient ? 'bg-green-50 text-green-700 dark:bg-green-900/20 dark:text-green-400 border border-green-100 dark:border-green-800' : 'bg-orange-50 text-orange-700 dark:bg-orange-900/20 dark:text-orange-400 border border-orange-100 dark:border-orange-800'}`} 
                                                        title={test.efficient ? 'Hardware Accelerated (Efficient)' : 'Software Decoding (Power Hungry)'}
                                                    >
                                                        {test.efficient ? <Battery size={12} /> : <Zap size={12} />}
                                                        <span className="text-[10px] font-medium hidden sm:inline">{test.efficient ? 'HW' : 'SW'}</span>
                                                    </div>
                                                    <div 
                                                        className={`flex items-center gap-1 px-1.5 py-0.5 rounded ${test.smooth ? 'bg-blue-50 text-blue-700 dark:bg-blue-900/20 dark:text-blue-400 border border-blue-100 dark:border-blue-800' : 'bg-red-50 text-red-700 dark:bg-red-900/20 dark:text-red-400 border border-red-100 dark:border-red-800'}`} 
                                                        title={test.smooth ? t.video_smooth : 'May Drop Frames'}
                                                    >
                                                        {test.smooth ? <Check size={12} /> : <X size={12} />}
                                                    </div>
                                                </div>
                                            )}
                                        </div>
                                    ))}
                                </div>
                            </div>
                        ))}
                    </div>
                </div>
            )}

            {/* Audio Section */}
            {filteredAudio.length > 0 && (
                <div className="mb-6">
                    <h3 className="text-xs font-bold text-slate-400 uppercase tracking-wider mb-3 flex items-center gap-2 px-1">
                        <Music size={14} />
                        {labels.audio_codecs}
                    </h3>
                    <div className="space-y-3">
                        {filteredAudio.map((row, rIdx) => (
                            <div key={rIdx} className="bg-white dark:bg-slate-800 rounded-xl border border-slate-200 dark:border-slate-700 overflow-hidden shadow-sm">
                                <div className="bg-slate-50 dark:bg-slate-900/50 px-4 py-2 border-b border-slate-100 dark:border-slate-700 flex items-center justify-between">
                                    <div className="flex items-center gap-2">
                                        <Speaker size={14} className="text-slate-400" />
                                        <h3 className="font-bold text-sm text-slate-800 dark:text-slate-100">{row.codec}</h3>
                                        <span className="text-xs text-slate-500 dark:text-slate-400 ml-1 hidden sm:inline">({row.label})</span>
                                    </div>
                                    <span className={`flex items-center gap-1 text-[10px] font-bold px-1.5 py-0.5 rounded border ${getTagColor(row.tag)}`}>
                                        {row.tag === 'Dolby' && <Tv size={10} />}
                                        {row.tag}
                                    </span>
                                </div>

                                <div className="grid grid-cols-3 divide-x divide-slate-100 dark:divide-slate-700">
                                    {row.tests.map((test: any, idx: number) => (
                                        <div key={idx} className={`p-3 flex flex-col gap-1 items-center justify-center text-center transition-colors ${test.supported ? '' : 'bg-slate-50/50 dark:bg-slate-800/30 opacity-60'}`}>
                                            <span className="text-[10px] font-bold text-slate-500 uppercase tracking-wide">{test.label}</span>

                                            {!test.supported ? (
                                                <span className="text-xs font-bold text-slate-300 dark:text-slate-600">{values.not_supported}</span>
                                            ) : (
                                                <div className="flex items-center gap-1.5">
                                                    <div 
                                                        className={`flex items-center justify-center w-6 h-6 rounded-full ${test.supported ? 'bg-emerald-100 text-emerald-600 dark:bg-emerald-900/30 dark:text-emerald-400' : 'bg-red-100 text-red-600'}`}
                                                    >
                                                        {test.supported ? <Check size={12} /> : <X size={12} />}
                                                    </div>
                                                    {test.efficient && (
                                                        <span className="text-[10px] font-bold text-emerald-600 dark:text-emerald-500 border border-emerald-200 dark:border-emerald-800/50 px-1.5 rounded">HW</span>
                                                    )}
                                                </div>
                                            )}
                                        </div>
                                    ))}
                                </div>
                            </div>
                        ))}
                    </div>
                </div>
            )}

            {/* Legend */}
            <div className="mt-4 flex gap-4 text-[10px] text-slate-400 justify-center pb-2 flex-wrap">
                <div className="flex items-center gap-1"><Battery size={12} className="text-green-500" /> {t.video_efficient}</div>
                <div className="flex items-center gap-1"><Zap size={12} className="text-orange-500" /> Software</div>
                <div className="flex items-center gap-1"><Check size={12} className="text-blue-500" /> {t.video_smooth}</div>
            </div>
        </div>
    );
};

