import React, { useState, useEffect, useRef, useTransition } from "react";
import {
  Monitor,
  RefreshCw,
  Download,
  Activity,
  Sun,
  Moon,
  Laptop,
  Sliders,
  Info,
  Languages,
  ChevronDown,
  Maximize,
  Minimize,
  MoreVertical,
  Loader2,
} from "lucide-react";
import { Translation, Language } from "../../utils/i18n/types";
import { Theme } from "../../appearance/theme";
import { useFormatter } from "../../hooks/useFormatter";
import { Button } from "../ui/Button";

// List of supported language codes
const SUPPORTED_LANGUAGES: Language[] = [
  "en",
  "zh-CN",
  "zh-TW",
  "zh-HK",
  "ja",
  "ru",
];

interface HeaderProps {
  t: Translation;
  lang: Language;
  setLang: (lang: Language) => void;
  theme: Theme;
  toggleTheme: () => void;
  onRefresh: () => void;
  onExport: () => void;
  onOpenSettings: () => void;
  onOpenAbout: () => void;
  onOpenBenchmark: () => void;
  collapseHeader?: boolean;
}

export const Header: React.FC<HeaderProps> = ({
  t,
  lang,
  setLang,
  theme,
  toggleTheme,
  onRefresh,
  onExport,
  onOpenSettings,
  onOpenAbout,
  onOpenBenchmark,
  collapseHeader = false,
}) => {
  const [isLangMenuOpen, setIsLangMenuOpen] = useState(false);
  const [isMoreMenuOpen, setIsMoreMenuOpen] = useState(false);
  const [isFullscreen, setIsFullscreen] = useState(false);
  const [pendingLang, setPendingLang] = useState<Language | null>(null);
  const [isPending, startTransition] = useTransition();
  const { formatNativeLanguageName } = useFormatter(lang);

  const langMenuRef = useRef<HTMLDivElement>(null);
  const moreMenuRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    const handleFullscreenChange = () => {
      setIsFullscreen(!!document.fullscreenElement);
    };
    document.addEventListener("fullscreenchange", handleFullscreenChange);
    return () =>
      document.removeEventListener("fullscreenchange", handleFullscreenChange);
  }, []);

  // Reset states when language actually changes!
  useEffect(() => {
    if (pendingLang === lang) {
      setPendingLang(null);
      setIsLangMenuOpen(false);
      setIsMoreMenuOpen(false);
    }
  }, [lang, pendingLang]);

  // Close menus when clicking outside
  useEffect(() => {
    const handleClickOutside = (e: MouseEvent) => {
      // Don't close if we are in the middle of a transition
      if (isPending) return;
      if (
        langMenuRef.current &&
        !langMenuRef.current.contains(e.target as Node)
      ) {
        setIsLangMenuOpen(false);
      }
      if (
        moreMenuRef.current &&
        !moreMenuRef.current.contains(e.target as Node)
      ) {
        setIsMoreMenuOpen(false);
      }
    };
    document.addEventListener("mousedown", handleClickOutside);
    return () => document.removeEventListener("mousedown", handleClickOutside);
  }, [isPending]);

  const toggleFullscreen = () => {
    if (!document.fullscreenElement) {
      document.documentElement.requestFullscreen().catch((err) => {
        console.error(`Error attempting to enable fullscreen: ${err.message}`);
      });
    } else {
      if (document.exitFullscreen) {
        document.exitFullscreen();
      }
    }
    setIsMoreMenuOpen(false);
  };

  const handleExport = () => {
    onExport();
    setIsMoreMenuOpen(false);
  };

  const handleAbout = () => {
    onOpenAbout();
    setIsMoreMenuOpen(false);
  };

  const handleLangSelect = (code: Language) => {
    if (code === lang) {
      setIsLangMenuOpen(false);
      setIsMoreMenuOpen(false);
      return;
    }
    setPendingLang(code);
    startTransition(() => {
      setLang(code);
    });
  };

  const useCollapsed = collapseHeader
    ? "hidden"
    : "hidden sm:inline-flex md:inline-flex lg:inline-flex";
  const mobileAlwaysHidden = "hidden lg:inline-flex";
  const displayClass = collapseHeader ? mobileAlwaysHidden : useCollapsed;

  return (
    <header className="flex flex-col md:flex-row md:items-end justify-between gap-4 pb-6 border-b border-slate-200 dark:border-slate-800 relative z-40">
      <div>
        <h1 className="text-3xl font-bold text-slate-900 dark:text-white tracking-tight flex items-center gap-3">
          <Monitor className="text-indigo-600 dark:text-indigo-400" size={32} />
          {t.meta.title}
        </h1>
        <p className="mt-2 text-slate-500 dark:text-slate-400 max-w-2xl">
          {t.meta.subtitle}
        </p>
      </div>
      <div className="flex gap-2 sm:gap-3 flex-wrap items-center">
        <Button
          variant="soft"
          onClick={onOpenBenchmark}
          leftIcon={<Activity size={16} />}
        >
          <span className="hidden sm:inline">{t.actions.run_benchmark}</span>
        </Button>

