          >
            {isFullscreen ? <Minimize size={16} /> : <Maximize size={16} />}
          </Button>

          <Button
            variant="secondary"
            onClick={onOpenAbout}
            title={t.actions.about}
          >
            <Info size={16} />
          </Button>

          <div className="relative" ref={langMenuRef}>
            <Button
              variant="secondary"
              onClick={() => setIsLangMenuOpen(!isLangMenuOpen)}
              leftIcon={<Languages size={16} />}
              rightIcon={
                <ChevronDown
                  size={14}
                  className={`transition-transform duration-300 ${isLangMenuOpen ? "rotate-180" : ""}`}
                />
              }
            >
              <span className="capitalize">
                {formatNativeLanguageName(lang)}
              </span>
            </Button>

            <div
              className={`absolute right-0 top-full mt-2 w-48 bg-white/90 dark:bg-slate-800/90 backdrop-blur-md border border-slate-200 dark:border-slate-700 rounded-lg shadow-xl py-1 z-50 transform transition-all duration-200 origin-top-right ${isLangMenuOpen ? "opacity-100 scale-100 translate-y-0" : "opacity-0 scale-95 -translate-y-2 pointer-events-none"}`}
            >
              {SUPPORTED_LANGUAGES.map((code) => {
                const isCurrent = lang === code;
                const isItemPending = isPending && pendingLang === code;

                return (
                  <button
                    key={code}
                    onClick={() => handleLangSelect(code as Language)}
                    disabled={isPending}
                    className={`w-full text-left px-4 py-2 text-sm flex items-center justify-between hover:bg-slate-50 dark:hover:bg-slate-700/50 transition-colors disabled:opacity-50 disabled:cursor-not-allowed ${isCurrent ? "text-indigo-600 dark:text-indigo-400 font-medium bg-indigo-50 dark:bg-indigo-900/20" : "text-slate-700 dark:text-slate-300"}`}
                  >
                    <span>{formatNativeLanguageName(code)}</span>
                    {isItemPending && (
                      <Loader2
                        size={14}
                        className="animate-spin text-indigo-500"
                      />
                    )}
                  </button>
                );
              })}
            </div>
          </div>

          <Button
            variant="secondary"
            onClick={onExport}
            leftIcon={<Download size={16} />}
          >
            <span className="hidden sm:inline">{t.actions.export_json}</span>
          </Button>
        </div>

        {/* The More menu visible when items are collapsed */}
        <div
          className={`relative ${collapseHeader ? "flex" : "flex lg:hidden"}`}
          ref={moreMenuRef}
        >
          <Button
            variant="secondary"
            onClick={() => setIsMoreMenuOpen(!isMoreMenuOpen)}
            title="More options"
          >
            <MoreVertical size={16} />
          </Button>

          <div
            className={`absolute right-0 top-full mt-2 w-48 bg-white/95 dark:bg-slate-800/95 backdrop-blur-xl border border-slate-200 dark:border-slate-700 rounded-xl shadow-2xl py-2 z-50 transform transition-all duration-200 origin-top-right flex flex-col ${isMoreMenuOpen ? "opacity-100 scale-100 translate-y-0" : "opacity-0 scale-95 -translate-y-2 pointer-events-none"}`}
          >
            <div className="px-3 pb-2 mb-1 text-[10px] font-bold text-slate-400 uppercase tracking-wider border-b border-slate-100 dark:border-slate-700">
              {t.common.menu || "Menu"}
            </div>

            <button
              onClick={toggleFullscreen}
              className="w-full text-left px-4 py-2 text-sm hover:bg-slate-50 dark:hover:bg-slate-700/50 flex items-center gap-3 text-slate-700 dark:text-slate-300 transition-colors"
            >
              <span className="text-slate-400">
                {isFullscreen ? <Minimize size={14} /> : <Maximize size={14} />}
              </span>
              {isFullscreen
                ? (t.common as any).exit_fullscreen || "Exit Fullscreen"
                : (t.common as any).fullscreen || "Fullscreen"}
            </button>

            <button
              onClick={handleAbout}
              className="w-full text-left px-4 py-2 text-sm hover:bg-slate-50 dark:hover:bg-slate-700/50 flex items-center gap-3 text-slate-700 dark:text-slate-300 transition-colors"
            >
              <span className="text-slate-400">
                <Info size={14} />
              </span>
              {t.actions.about}
            </button>

            <button
              onClick={handleExport}
              className="w-full text-left px-4 py-2 text-sm hover:bg-slate-50 dark:hover:bg-slate-700/50 flex items-center gap-3 text-slate-700 dark:text-slate-300 transition-colors"
            >
              <span className="text-slate-400">
                <Download size={14} />
              </span>
              {t.actions.export_json}
            </button>

            <div className="mt-1 pt-1 border-t border-slate-100 dark:border-slate-700">
              <div className="px-3 py-1.5 text-[10px] font-bold text-slate-400 uppercase tracking-wider">
                {t.common.language || "Language"}
              </div>
              {SUPPORTED_LANGUAGES.map((code) => {
                const isCurrent = lang === code;
                const isItemPending = isPending && pendingLang === code;

                return (
                  <button
                    key={code}
                    onClick={() => handleLangSelect(code as Language)}
                    disabled={isPending}
                    className={`w-full text-left px-4 py-2 text-sm hover:bg-slate-50 dark:hover:bg-slate-700/50 transition-colors flex items-center gap-2 justify-between disabled:opacity-50 disabled:cursor-not-allowed ${isCurrent ? "text-indigo-600 dark:text-indigo-400 font-medium" : "text-slate-600 dark:text-slate-300"}`}
                  >
                    <div className="flex items-center gap-2">
                      {isCurrent && (
                        <div className="w-1.5 h-1.5 rounded-full bg-indigo-500"></div>
                      )}
                      <span className={isCurrent ? "" : "ml-3"}>
                        {formatNativeLanguageName(code)}
                      </span>
                    </div>
                    {isItemPending && (
                      <Loader2
                        size={14}
                        className="animate-spin text-indigo-500"
                      />
                    )}
                  </button>
                );
              })}
            </div>
          </div>
        </div>

        <Button
          variant="primary"
          onClick={onRefresh}
          leftIcon={<RefreshCw size={16} />}
        >
          <span className="hidden sm:inline">{t.common.refresh}</span>
        </Button>
      </div>
    </header>
  );
};

import React, { useEffect, useState } from 'react';
import { Translation } from '../../utils/i18n/types';

import { Select } from '../ui/Select';

interface GeneralTabProps {
    t: any; // Using any for t because Translation type was getting complicated with extensions
    themeColor: string;
    setThemeColor: (color: string) => void;
    animationStyle: string;
    setAnimationStyle: (style: string) => void;
    simpleMode: boolean;
    toggleSimpleMode: (value: boolean) => void;
    hideScrollbar: boolean;
    toggleHideScrollbar: (value: boolean) => void;
    globalHideScrollbar: boolean;
    toggleGlobalHideScrollbar: (value: boolean) => void;
    timeFormat: '12' | '24';
    setTimeFormat: (format: '12' | '24') => void;
    disableBlur: boolean;
    toggleDisableBlur: (value: boolean) => void;
    disableAnimations: boolean;
    toggleDisableAnimations: (value: boolean) => void;
    fastAnimations: boolean;
    toggleFastAnimations: (value: boolean) => void;
    collapseHeader: boolean;
    toggleCollapseHeader: (value: boolean) => void;
    enableUdp?: boolean;
    toggleEnableUdp?: (value: boolean) => void;
    hiddenCards: string[];
    setHiddenCards: (cards: string[]) => void;
    translationDict: any;
}

// Custom Switch Component with Spring Animation
const Switch: React.FC<{ checked: boolean; onChange: (val: boolean) => void; label?: string; disabled?: boolean }> = ({ checked, onChange, label, disabled = false }) => (
    <button
        role="switch"
        aria-checked={checked}
        aria-label={label}
        onClick={() => !disabled && onChange(!checked)}
        disabled={disabled}
        className={`
            relative inline-flex h-8 w-14 shrink-0 cursor-pointer items-center rounded-full border-2 border-transparent 
            transition-colors duration-300 ease-in-out focus:outline-none focus:ring-2 focus:ring-indigo-500/50 focus:ring-offset-2 dark:focus:ring-offset-slate-800
            ${checked ? 'bg-indigo-600' : 'bg-slate-200 dark:bg-slate-700'}
            ${disabled ? 'opacity-50 cursor-not-allowed' : ''}
        `}
    >
        <span className="sr-only">{label}</span>
        <span
            aria-hidden="true"
            className={`
                pointer-events-none inline-block h-6 w-6 transform rounded-full bg-white shadow-lg ring-0 
                transition duration-300 ease-[cubic-bezier(0.34,1.56,0.64,1)]
                ${checked ? 'translate-x-6' : 'translate-x-0'}
            `}
        />
    </button>
);

export const GeneralTab: React.FC<GeneralTabProps> = ({ 
    t, 
    themeColor,
    setThemeColor,
    animationStyle,
    setAnimationStyle,
    simpleMode, 
    toggleSimpleMode, 
    hideScrollbar, 
    toggleHideScrollbar,
    globalHideScrollbar,
    toggleGlobalHideScrollbar,
    timeFormat,
    setTimeFormat,
    disableBlur,
    toggleDisableBlur,
    disableAnimations,
    toggleDisableAnimations,
    fastAnimations,
    toggleFastAnimations,
    collapseHeader,
    toggleCollapseHeader,
    enableUdp,
    toggleEnableUdp,
    hiddenCards,
    setHiddenCards,
    translationDict
}) => {
    const [udpSupported, setUdpSupported] = useState<boolean | null>(null);

    useEffect(() => {
        if (toggleEnableUdp) {
            fetch('/api/udp-status')
                .then(res => res.json())
                .then(data => setUdpSupported(data.supported))
                .catch(() => setUdpSupported(false));
        }
    }, [toggleEnableUdp]);

    // Collect all card names using the translation dictionary.
    // Note: If translations are added dynamically or missing in dict, we provide fallbacks.
    const sectionsObj = translationDict?.sections || {};
    const availableCards = [
        { id: 'environment', name: sectionsObj.environment || 'Analysis Environment' },
        { id: 'system', name: sectionsObj.system || 'System Environment' },
        { id: 'hardware', name: sectionsObj.hardware || 'Hardware Info' },
        { id: 'display', name: sectionsObj.display || 'Display Info' },
        { id: 'network', name: sectionsObj.network || 'Network & IP' },
        { id: 'security', name: sectionsObj.security || 'Security & Tracking' },
        { id: 'fingerprint', name: sectionsObj.fingerprints || 'Fingerprint' },
        { id: 'ai', name: sectionsObj.ai_compute || 'AI & Compute' },
        { id: 'location', name: sectionsObj.location || 'Location & Sensors' },
        { id: 'storage', name: sectionsObj.storage || 'Storage Insights' },
        { id: 'permissions', name: sectionsObj.permissions || 'Permissions' },
        { id: 'media_devices', name: sectionsObj.media_devices || 'Media Devices' },
        { id: 'media_capabilities', name: sectionsObj.media_caps || 'Media Capabilities' },
        { id: 'user_agent', name: sectionsObj.user_agent || 'User Agent' },
        { id: 'pwa', name: sectionsObj.pwa || 'PWA Support' },
        { id: 'features', name: sectionsObj.features || 'Features' },
    ];

    const toggleCardHide = (id: string) => {
        if (hiddenCards.includes(id)) {
            setHiddenCards(hiddenCards.filter(c => c !== id));
        } else {
            setHiddenCards([...hiddenCards, id]);
        }
    };
    return (
        <div className="max-w-2xl mx-auto space-y-4">
            {/* Simple Mode Toggle */}
            <div 
                className="bg-white dark:bg-slate-800 p-5 rounded-xl border border-slate-200 dark:border-slate-700 shadow-sm flex items-center justify-between cursor-pointer transition-colors hover:border-indigo-200 dark:hover:border-indigo-800"
                onClick={() => toggleSimpleMode(!simpleMode)}
            >
                <div className="flex flex-col gap-1 pr-4">
                    <h3 className="font-semibold text-slate-800 dark:text-slate-100 flex items-center gap-2">
                        {t.simpleMode.title}
                    </h3>
                    <p className="text-sm text-slate-500 dark:text-slate-400 max-w-sm leading-relaxed">
                        {t.simpleMode.desc}
                    </p>
                </div>
                <div onClick={(e) => e.stopPropagation()}>
                    <Switch 
                        checked={simpleMode} 
                        onChange={toggleSimpleMode} 
                        label={t.simpleMode.title} 
                    />
                </div>
            </div>

            {/* Time Format Toggle */}
            <div 
                className="bg-white dark:bg-slate-800 p-5 rounded-xl border border-slate-200 dark:border-slate-700 shadow-sm flex items-center justify-between cursor-pointer transition-colors hover:border-indigo-200 dark:hover:border-indigo-800"
                onClick={() => setTimeFormat(timeFormat === '24' ? '12' : '24')}
            >
                <div className="flex flex-col gap-1 pr-4">
                    <h3 className="font-semibold text-slate-800 dark:text-slate-100 flex items-center gap-2">
                        {t.timeFormat.title}
                    </h3>
                    <p className="text-sm text-slate-500 dark:text-slate-400 max-w-sm leading-relaxed">
                        {t.timeFormat.desc}
                    </p>
                </div>
                <div onClick={(e) => e.stopPropagation()}>
                    <Switch 
                        checked={timeFormat === '24'} 
                        onChange={(val) => setTimeFormat(val ? '24' : '12')} 
                        label={t.timeFormat.title} 
                    />
                </div>
            </div>

            {/* Theme Color Selection */}
            <div className="bg-white dark:bg-slate-800 p-5 rounded-xl border border-slate-200 dark:border-slate-700 shadow-sm flex flex-col sm:flex-row items-start sm:items-center justify-between gap-4">
                <div className="flex flex-col gap-1 pr-4">
                    <h3 className="font-semibold text-slate-800 dark:text-slate-100 flex items-center gap-2">
                        {translationDict.settings?.general?.themeColor?.title || 'Theme Color'}
                    </h3>
                    <p className="text-sm text-slate-500 dark:text-slate-400 max-w-sm leading-relaxed">
                        {translationDict.settings?.general?.themeColor?.desc || 'Select primary theme color for the application.'}
                    </p>
                </div>
                <div className="flex bg-slate-100 dark:bg-slate-900/50 p-1 rounded-lg self-stretch sm:self-auto flex-wrap gap-1">
                    {[
                        { id: 'indigo', hex: '#6366f1' },
                        { id: 'emerald', hex: '#10b981' },
                        { id: 'rose', hex: '#f43f5e' },
                        { id: 'amber', hex: '#f59e0b' },
                        { id: 'blue', hex: '#3b82f6' },
                        { id: 'violet', hex: '#8b5cf6' },
                        { id: 'sky', hex: '#77bbee' },
                        { id: 'ice', hex: '#a7c8ff' },
                        { id: 'cherry', hex: '#efa7a8' }
                    ].map(theme => (
                        <button
                            key={theme.id}
                            onClick={() => setThemeColor(theme.id)}
                            className={`w-8 h-8 rounded-md transition-all flex items-center justify-center ${themeColor === theme.id ? 'ring-2 ring-slate-800 dark:ring-white scale-110 shadow-sm' : 'hover:scale-105'}`}
                            style={{ backgroundColor: theme.hex }}
                            title={theme.id}
                        >
                            {themeColor === theme.id && <div className="w-2 h-2 rounded-full bg-white dark:bg-slate-900" />}
                        </button>
                    ))}
                </div>
            </div>

            {/* Animation Style Selection */}
            <div className="bg-white dark:bg-slate-800 p-5 rounded-xl border border-slate-200 dark:border-slate-700 shadow-sm flex flex-col sm:flex-row items-start sm:items-center justify-between gap-4">
                <div className="flex flex-col gap-1 pr-4">
                    <h3 className="font-semibold text-slate-800 dark:text-slate-100 flex items-center gap-2">
                        {translationDict.settings?.general?.animationStyle?.title || 'Animation Style'}
                    </h3>
                    <p className="text-sm text-slate-500 dark:text-slate-400 max-w-sm leading-relaxed">
                        {translationDict.settings?.general?.animationStyle?.desc || 'Set entry component animation style.'}
                    </p>
                </div>
                <Select 
                    value={animationStyle}
                    onChange={setAnimationStyle}
                    options={[
                        { id: 'slide-up', label: translationDict.settings?.general?.animationStyle?.options?.slideUp || 'Slide Up' },
                        { id: 'fade', label: translationDict.settings?.general?.animationStyle?.options?.fade || 'Fade In' },
                        { id: 'fly-in', label: translationDict.settings?.general?.animationStyle?.options?.flyIn || 'Fly In' },
                        { id: 'zoom', label: translationDict.settings?.general?.animationStyle?.options?.zoom || 'Zoom In' }
                    ]}
                    className="w-full sm:w-48"
                    color={themeColor as any}
                />
            </div>

            {/* Disable Blur (Renamed from High Performance) */}
            <div 
                className="bg-white dark:bg-slate-800 p-5 rounded-xl border border-slate-200 dark:border-slate-700 shadow-sm flex items-center justify-between cursor-pointer transition-colors hover:border-indigo-200 dark:hover:border-indigo-800"
                onClick={() => toggleDisableBlur(!disableBlur)}
            >
                <div className="flex flex-col gap-1 pr-4">
                    <h3 className="font-semibold text-slate-800 dark:text-slate-100 flex items-center gap-2">
                        {t.performance.title}
                    </h3>
                    <p className="text-sm text-slate-500 dark:text-slate-400 max-w-sm leading-relaxed">
                        {t.performance.desc}
                    </p>
                </div>
                <div onClick={(e) => e.stopPropagation()}>
                    <Switch 
                        checked={disableBlur} 
                        onChange={toggleDisableBlur} 
                        label={t.performance.title} 
                    />
                </div>
            </div>

            {/* Hide Scrollbar Toggle */}
            <div 
                className={`p-5 rounded-xl border shadow-sm flex items-center justify-between transition-colors ${globalHideScrollbar ? 'bg-slate-50 dark:bg-slate-900 border-slate-100 dark:border-slate-800 opacity-50 cursor-not-allowed' : 'bg-white dark:bg-slate-800 border-slate-200 dark:border-slate-700 cursor-pointer hover:border-indigo-200 dark:hover:border-indigo-800'}`}
                onClick={() => { if (!globalHideScrollbar) toggleHideScrollbar(!hideScrollbar); }}
            >
                <div className="flex flex-col gap-1 pr-4">
                    <h3 className="font-semibold text-slate-800 dark:text-slate-100 flex items-center gap-2">
                        {t.scrollbar?.title || "Hide Main Page Scrollbar"}
                    </h3>
                    <p className="text-sm text-slate-500 dark:text-slate-400 max-w-sm leading-relaxed">
                        {t.scrollbar?.desc || "Only hide the default scrollbar on the main page."}
                    </p>
                </div>
                <div onClick={(e) => e.stopPropagation()}>
                    <Switch 
                        checked={hideScrollbar || globalHideScrollbar} 
                        onChange={(val) => { if (!globalHideScrollbar) toggleHideScrollbar(val); }} 
                        label={t.scrollbar?.title || "Hide Main Page Scrollbar"} 
                        disabled={globalHideScrollbar}
                    />
                </div>
            </div>

            {/* Global Hide Scrollbar Toggle */}
            <div 
                className="bg-white dark:bg-slate-800 p-5 rounded-xl border border-slate-200 dark:border-slate-700 shadow-sm flex items-center justify-between cursor-pointer transition-colors hover:border-indigo-200 dark:hover:border-indigo-800"
                onClick={() => toggleGlobalHideScrollbar(!globalHideScrollbar)}
            >
                <div className="flex flex-col gap-1 pr-4">
                    <h3 className="font-semibold text-slate-800 dark:text-slate-100 flex items-center gap-2">
                        {t.globalScrollbar?.title || "Hide All Scrollbars"}
                    </h3>
                    <p className="text-sm text-slate-500 dark:text-slate-400 max-w-sm leading-relaxed">
                        {t.globalScrollbar?.desc || "Globally hide scrollbars for all elements, including inside modals."}
                    </p>
                </div>
                <div onClick={(e) => e.stopPropagation()}>
                    <Switch 
                        checked={globalHideScrollbar} 
                        onChange={toggleGlobalHideScrollbar} 
                        label={t.globalScrollbar?.title || "Hide All Scrollbars"} 
                    />
                </div>
            </div>
            {/* Disable Animations */}
            <div 
                className="bg-white dark:bg-slate-800 p-5 rounded-xl border border-slate-200 dark:border-slate-700 shadow-sm flex items-center justify-between cursor-pointer transition-colors hover:border-indigo-200 dark:hover:border-indigo-800"
                onClick={() => toggleDisableAnimations(!disableAnimations)}
            >
                <div className="flex flex-col gap-1 pr-4">
                    <h3 className="font-semibold text-slate-800 dark:text-slate-100 flex items-center gap-2">
                        {t.animations?.title || 'Disable Animations'}
                    </h3>
                    <p className="text-sm text-slate-500 dark:text-slate-400 max-w-sm leading-relaxed">
                        {t.animations?.desc || 'Turn off all page transitions and card loading animations.'}
                    </p>
                </div>
                <div onClick={(e) => e.stopPropagation()}>
                    <Switch 
                        checked={disableAnimations} 
                        onChange={toggleDisableAnimations} 
                        label={t.animations?.title} 
                    />
                </div>
            </div>

            {/* Fast Animations */}
            <div 
                className={`p-5 rounded-xl border shadow-sm flex items-center justify-between transition-colors ${disableAnimations ? 'opacity-50 cursor-not-allowed bg-slate-50 dark:bg-slate-900 border-slate-100 dark:border-slate-800' : 'bg-white dark:bg-slate-800 border-slate-200 dark:border-slate-700 cursor-pointer hover:border-indigo-200 dark:hover:border-indigo-800'}`}
                onClick={() => { if (!disableAnimations) toggleFastAnimations(!fastAnimations); }}
            >
                <div className="flex flex-col gap-1 pr-4">
                    <h3 className="font-semibold text-slate-800 dark:text-slate-100 flex items-center gap-2">
                        {t.fastAnimations?.title || 'Fast Transitions'}
                    </h3>
                    <p className="text-sm text-slate-500 dark:text-slate-400 max-w-sm leading-relaxed">
                        {t.fastAnimations?.desc || 'Speed up all transition animations (hover, expand, etc).'}
                    </p>
                </div>
                <div onClick={(e) => e.stopPropagation()}>
                    <Switch 
                        checked={fastAnimations} 
                        onChange={toggleFastAnimations} 
                        label={t.fastAnimations?.title}
                        disabled={disableAnimations} 
                    />
                </div>
            </div>

            {/* Collapse Header Menu Desktop */}
            <div 
                className="p-5 rounded-xl border shadow-sm flex items-center justify-between transition-colors bg-white dark:bg-slate-800 border-slate-200 dark:border-slate-700 cursor-pointer hover:border-indigo-200 dark:hover:border-indigo-800 max-lg:opacity-50 max-lg:cursor-not-allowed max-lg:bg-slate-50 max-lg:dark:bg-slate-900 max-lg:border-slate-100 max-lg:dark:border-slate-800"
                onClick={() => { if (window.innerWidth >= 1024) toggleCollapseHeader(!collapseHeader); }}
            >
                <div className="flex flex-col gap-1 pr-4">
                    <h3 className="font-semibold text-slate-800 dark:text-slate-100 flex items-center gap-2">
                        {t.collapseHeader?.title || 'Collapse Header (Desktop)'}
                    </h3>
                    <p className="text-sm text-slate-500 dark:text-slate-400 max-w-sm leading-relaxed">
                        {t.collapseHeader?.desc || 'Use a collapsed menu for header actions on desktop screens.'}
                    </p>
                </div>
                <div onClick={(e) => e.stopPropagation()}>
                    <Switch 
                        checked={collapseHeader} 
                        onChange={toggleCollapseHeader} 
                        label={t.collapseHeader?.title} 
                    />
                </div>
            </div>

            {/* Enable UDP Toggle */}
            {toggleEnableUdp && (
                <div 
                    className={`p-5 rounded-xl border shadow-sm flex items-center justify-between transition-colors ${!udpSupported ? 'opacity-50 cursor-not-allowed bg-slate-50 dark:bg-slate-900 border-slate-100 dark:border-slate-800' : 'bg-white dark:bg-slate-800 border-slate-200 dark:border-slate-700 cursor-pointer hover:border-indigo-200 dark:hover:border-indigo-800'}`}
                    onClick={() => { if (udpSupported) toggleEnableUdp(!enableUdp); }}
                >
                    <div className="flex flex-col gap-1 pr-4">
                        <h3 className="font-semibold text-slate-800 dark:text-slate-100 flex items-center gap-2">
                            {t.udpBypass?.title || 'Enable UDP Network (Bypass CORS)'}
                        </h3>
                        <p className="text-sm text-slate-500 dark:text-slate-400 max-w-sm leading-relaxed">
                            {t.udpBypass?.desc || 'Use UDP mapping API to fetch network tools endpoints entirely bypassing all CORS errors.'}
                        </p>
                        {!udpSupported && udpSupported !== null && (
                            <p className="text-xs text-rose-500 font-medium mt-1">
                                {t.udpBypass?.unsupportedEnv || 'Not supported in the current environment'}
                            </p>
                        )}
                        {udpSupported === null && (
                            <p className="text-xs text-indigo-500 font-medium mt-1 animate-pulse">
                                Checking UDP support...
                            </p>
                        )}
                    </div>
                    <div>
                        <Switch 
                            checked={!!enableUdp} 
                            onChange={() => { if(udpSupported) toggleEnableUdp(!enableUdp); }} 
                            label={t.udpBypass?.title || 'Enable UDP'} 
                            disabled={!udpSupported}
                        />
                    </div>
                </div>
            )}

            {/* Custom Visibility */}
            <div className="bg-white dark:bg-slate-800 p-5 rounded-xl border border-slate-200 dark:border-slate-700 shadow-sm space-y-4">
                <div className="flex flex-col gap-1">
                    <h3 className="font-semibold text-slate-800 dark:text-slate-100 flex items-center gap-2">
                        {t.cardVisibility?.title || 'Custom Display Items'}
                    </h3>
                    <p className="text-sm text-slate-500 dark:text-slate-400 leading-relaxed">
                        {t.cardVisibility?.desc || 'Hide specific cards from the main dashboard if you don\'t need them.'}
                    </p>
                </div>
                <div className="grid grid-cols-2 sm:grid-cols-3 gap-3">
                    {availableCards.map(card => {
                        const isHidden = hiddenCards.includes(card.id);
                        return (
                            <button
                                key={card.id}
                                onClick={() => toggleCardHide(card.id)}
                                className={`
                                    flex items-center gap-2 p-2 rounded-lg text-sm font-medium transition-colors border text-left
                                    ${isHidden 
                                        ? 'bg-slate-50 dark:bg-slate-800 border-slate-200 dark:border-slate-700 text-slate-400 dark:text-slate-500 line-through' 
                                        : 'bg-indigo-50 dark:bg-indigo-900/30 border-indigo-200 dark:border-indigo-800 text-indigo-700 dark:text-indigo-400'}
                                `}
                            >
                                <div className={`w-3 h-3 rounded-full flex-shrink-0 ${isHidden ? 'bg-slate-300 dark:bg-slate-600' : 'bg-indigo-500'}`} />
                                <span className="truncate">{card.name}</span>
                            </button>
                        );
                    })}
                </div>
            </div>
        </div>
    );
};

import React from 'react';
import { Translation } from '../../utils/i18n/types';
import { Button } from '../ui/Button';
import { Badge } from '../ui/Badge';
import { Package, Power, Zap, ShieldCheck, Activity, CircleOff, Lock, Archive, Trash2 } from 'lucide-react';

export interface ModuleState {
    id: string;
    name: string;
    isOpen: boolean;
    setOpen: (val: boolean) => void;
    impact: 'High' | 'Medium' | 'Low';
    isSystem?: boolean;
    isLoaded?: boolean;
    onUnload?: () => void; // New callback for real unloading
}

interface ModulesTabProps {
    t: Translation['settings']['modules'];
    modules: ModuleState[];
}

export const ModulesTab: React.FC<ModulesTabProps> = ({ t, modules }) => {

    const activeCount = modules.filter(m => m.isOpen).length;
    const cachedCount = modules.filter(m => !m.isOpen && m.isLoaded).length;
    const idleCount = modules.filter(m => !m.isOpen && !m.isLoaded).length;

    const activeOrLoadedNonSystemCount = modules.filter(m => !m.isSystem && (m.isOpen || m.isLoaded)).length;

    // Sorting: Active > Loaded > Inactive
    const sortedModules = [...modules].sort((a, b) => {
        if (a.isOpen && !b.isOpen) return -1;
        if (!a.isOpen && b.isOpen) return 1;
        if (a.isLoaded && !b.isLoaded) return -1;
        if (!a.isLoaded && b.isLoaded) return 1;
        return 0;
    });

    const closeAll = () => {
        modules.forEach(m => {
            if (!m.isSystem && (m.isOpen || m.isLoaded)) {
                // If onUnload is present, use it to fully reset
                if (m.onUnload) m.onUnload();
                else m.setOpen(false);
            }
        });
    };

    const getImpactColor = (impact: string) => {
        switch(impact) {
            case 'High': return 'error';
            case 'Medium': return 'warning';
            case 'Low': return 'success';
            default: return 'neutral';
        }
    };

    const getImpactLabel = (impact: string) => {
        switch(impact) {
            case 'High': return t.impact.high;
            case 'Medium': return t.impact.med;
            case 'Low': return t.impact.low;
            default: return impact;
        }
    };

    return (
        <div className="space-y-6">
            {/* Header / Summary */}
            <div className="flex flex-col xl:flex-row justify-between items-start xl:items-center gap-4 bg-white dark:bg-slate-800 p-5 rounded-xl border border-slate-200 dark:border-slate-700 shadow-sm">
                <div>
                    <h3 className="font-bold text-slate-800 dark:text-slate-100 flex items-center gap-2 text-lg">
                        <Package size={22} className="text-indigo-500" />
                        {t.title}
                    </h3>
                    <p className="text-sm text-slate-500 dark:text-slate-400 mt-1 max-w-md leading-relaxed">
                        {t.desc}
                    </p>
                </div>

                <div className="flex flex-col sm:flex-row items-stretch sm:items-center gap-4 bg-slate-50 dark:bg-slate-900/50 p-3 rounded-xl border border-slate-100 dark:border-slate-700/50 w-full xl:w-auto">

                    {/* Stats Group */}
                    <div className="flex items-center justify-around sm:justify-start gap-4 sm:gap-6 flex-1">
                        {/* Active */}
                        <div className="text-center min-w-[3rem]">
                            <div className="text-[10px] text-emerald-600 dark:text-emerald-400 uppercase tracking-wider font-bold mb-0.5">{t.status.active}</div>
                            <div className="text-xl font-mono font-bold text-slate-700 dark:text-slate-200 leading-none">{activeCount}</div>
                        </div>

                        <div className="w-px h-8 bg-slate-200 dark:bg-slate-700"></div>

                        {/* Cached */}
                        <div className="text-center min-w-[3rem]">
                            <div className="text-[10px] text-blue-600 dark:text-blue-400 uppercase tracking-wider font-bold mb-0.5">{t.status.cached}</div>
                            <div className="text-xl font-mono font-bold text-slate-700 dark:text-slate-200 leading-none">{cachedCount}</div>
                        </div>

                        <div className="w-px h-8 bg-slate-200 dark:bg-slate-700"></div>

                        {/* Idle */}
                        <div className="text-center min-w-[3rem]">
                            <div className="text-[10px] text-slate-400 uppercase tracking-wider font-bold mb-0.5">{t.status.inactive}</div>
                            <div className="text-xl font-mono font-bold text-slate-700 dark:text-slate-200 leading-none">{idleCount}</div>
                        </div>
                    </div>

                    <div className="w-full h-px sm:w-px sm:h-8 bg-slate-200 dark:bg-slate-700 mx-2 hidden sm:block"></div>

                    <Button 
                        variant="danger-soft" 
                        size="sm" 
                        onClick={closeAll}
                        disabled={activeOrLoadedNonSystemCount === 0}
                        leftIcon={<Power size={16} />}
                        className="whitespace-nowrap justify-center"
                    >
                        {t.actions.unloadAll}
                    </Button>
                </div>
            </div>

            {/* List */}
            <div className="bg-white dark:bg-slate-800 rounded-xl border border-slate-200 dark:border-slate-700 overflow-hidden shadow-sm">
                <table className="w-full text-left text-sm">
                    <thead className="bg-slate-50 dark:bg-slate-900/50 border-b border-slate-200 dark:border-slate-700">
                        <tr>
                            <th className="px-5 py-3 font-semibold text-slate-500 dark:text-slate-400 text-xs uppercase tracking-wider w-1/3">{t.headers.name}</th>
                            <th className="px-5 py-3 font-semibold text-slate-500 dark:text-slate-400 text-xs uppercase tracking-wider">{t.headers.status}</th>
                            <th className="px-5 py-3 font-semibold text-slate-500 dark:text-slate-400 text-xs uppercase tracking-wider">{t.headers.impact}</th>
                            <th className="px-5 py-3 font-semibold text-slate-500 dark:text-slate-400 text-xs uppercase tracking-wider text-right">{t.headers.action}</th>
                        </tr>
                    </thead>
                    <tbody className="divide-y divide-slate-100 dark:divide-slate-700">
                        {sortedModules.map((mod) => (
                            <tr key={mod.id} className="hover:bg-slate-50 dark:hover:bg-slate-700/30 transition-colors group">
                                <td className="px-5 py-4">
                                    <div className="flex items-center gap-3">
                                        <div className={`p-2 rounded-lg ${mod.isOpen ? 'bg-indigo-50 dark:bg-indigo-900/20 text-indigo-600 dark:text-indigo-400' : 'bg-slate-100 dark:bg-slate-800 text-slate-400'}`}>
                                            {mod.isSystem ? <ShieldCheck size={18} /> : <Package size={18} />}
                                        </div>
                                        <div className="flex flex-col">
                                            <span className={`font-semibold ${mod.isOpen ? 'text-slate-900 dark:text-white' : 'text-slate-500 dark:text-slate-400'}`}>
                                                {mod.name}
                                            </span>
                                            {mod.isSystem && (
                                                <span className="text-[10px] text-slate-400 leading-none">{t.status.system}</span>
                                            )}
                                        </div>
                                    </div>
                                </td>
                                <td className="px-5 py-4">
                                    {mod.isOpen ? (
                                        <div className="inline-flex items-center gap-1.5 px-2.5 py-1 rounded-full bg-emerald-50 dark:bg-emerald-900/20 border border-emerald-100 dark:border-emerald-900/30">
                                            <span className="relative flex h-2 w-2">
                                              <span className="animate-ping absolute inline-flex h-full w-full rounded-full bg-emerald-400 opacity-75"></span>
                                              <span className="relative inline-flex rounded-full h-2 w-2 bg-emerald-500"></span>
                                            </span>
                                            <span className="text-xs font-bold text-emerald-700 dark:text-emerald-400">{t.status.active}</span>
                                        </div>
                                    ) : mod.isLoaded ? (
                                        <div className="inline-flex items-center gap-1.5 px-2.5 py-1 rounded-full bg-blue-50 dark:bg-blue-900/20 border border-blue-100 dark:border-blue-900/30">
                                            <span className="w-2 h-2 rounded-full bg-blue-500"></span>
                                            <span className="text-xs font-bold text-blue-700 dark:text-blue-400">{t.status.cached}</span>
                                        </div>
                                    ) : (
                                        <div className="inline-flex items-center gap-1.5 px-2.5 py-1 rounded-full bg-slate-100 dark:bg-slate-800 border border-slate-200 dark:border-slate-700">
                                            <CircleOff size={10} className="text-slate-400" />
                                            <span className="text-xs font-medium text-slate-500 dark:text-slate-400">{t.status.inactive}</span>
                                        </div>
                                    )}
                                </td>
                                <td className="px-5 py-4">
                                    <Badge variant={getImpactColor(mod.impact) as any} icon={<Zap size={10} />}>
                                        {getImpactLabel(mod.impact)}
                                    </Badge>
                                </td>
                                <td className="px-5 py-4 text-right">
                                    {mod.isSystem ? (
                                        <div className="inline-flex items-center gap-1 px-3 py-1.5 rounded-lg bg-slate-100 dark:bg-slate-800 text-slate-400 text-xs font-medium cursor-not-allowed select-none opacity-60">
                                            <Lock size={12} />
                                            <span>Locked</span>
                                        </div>
                                    ) : (
                                        <Button
                                            onClick={() => mod.onUnload ? mod.onUnload() : mod.setOpen(false)}
                                            disabled={!mod.isOpen && !mod.isLoaded}
                                            variant={mod.isOpen ? "danger-soft" : "secondary"}
                                            size="xs"
                                            leftIcon={mod.isOpen ? <Power size={14} /> : <Trash2 size={14} />}
                                            className={!mod.isOpen && !mod.isLoaded ? "opacity-0" : "transition-opacity"}
                                        >
                                            {t.actions.unload}
                                        </Button>
                                    )}
                                </td>
                            </tr>
                        ))}
                    </tbody>
                </table>
            </div>
        </div>
    );
};

import React, { useState, useEffect } from 'react';
