import React, { useState, useRef, useEffect } from "react";
import {
  ChevronRight,
  TriangleAlert,
  Check,
  Copy,
  Download,
  Trash2,
  Command,
  Zap,
  Globe,
  Smartphone,
  Shield,
  Edit3,
  Eye,
  Database,
  Activity,
  X,
  Play,
} from "lucide-react";
import { Translation } from "../../../utils/i18n/types";
import { loggerStore, ConsoleEntry } from "../../../utils/loggerStore";

interface ConsoleViewProps {
  t: Translation["settings"]["developer"];
  consoleHistory: ConsoleEntry[];
}

interface PresetCommand {
  id: keyof Translation["settings"]["developer"]["console"]["presets"];
  cmd: string;
  icon: React.ElementType;
  autoRun?: boolean;
}

const PRESET_COMMANDS: PresetCommand[] = [
  { id: "userAgent", cmd: "navigator.userAgent", icon: Globe, autoRun: true },
  {
    id: "screenInfo",
    cmd: "`${window.innerWidth}x${window.innerHeight} (PR: ${window.devicePixelRatio})`",
    icon: Smartphone,
    autoRun: true,
  },
  { id: "cookies", cmd: "document.cookie", icon: Shield, autoRun: true },
  {
    id: "clearStorage",
    cmd: 'localStorage.clear(); "LocalStorage Cleared"',
    icon: Trash2,
    autoRun: true,
  },
  {
    id: "editPage",
    cmd: 'document.body.contentEditable = document.body.contentEditable === "true" ? "false" : "true"',
    icon: Edit3,
    autoRun: true,
  },
  {
    id: "disableBlur",
    cmd: 'document.body.classList.toggle("no-blur")',
    icon: Eye,
    autoRun: true,
  },
  {
    id: "blockClicks",
    cmd: 'document.body.style.pointerEvents = document.body.style.pointerEvents === "none" ? "auto" : "none"',
    icon: Shield,
    autoRun: true,
  },
  {
    id: "getKeys",
    cmd: "Object.keys(localStorage)",
    icon: Database,
    autoRun: true,
  },
  {
    id: "reload",
    cmd: "window.location.reload()",
    icon: Activity,
    autoRun: true,
  },
  {
    id: "performance",
    cmd: "performance.now()",
    icon: Activity,
    autoRun: true,
  },
  { id: "network", cmd: "navigator.connection", icon: Activity, autoRun: true },
  { id: "memory", cmd: "performance.memory", icon: Database, autoRun: true },
];

export const ConsoleView: React.FC<ConsoleViewProps> = ({ t, consoleHistory }) => {
  const [inputCmd, setInputCmd] = useState("");
  const [showPresets, setShowPresets] = useState(false);
  const [consoleCopied, setConsoleCopied] = useState(false);
  const consoleEndRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    consoleEndRef.current?.scrollIntoView({ behavior: "smooth" });
  }, [consoleHistory]);

  const runConsole = (cmdOverride?: string) => {
    const cmdToRun = cmdOverride || inputCmd;
    if (!cmdToRun.trim()) return;

    setShowPresets(false);
    if (!cmdOverride) {
      setInputCmd("");
    }

    loggerStore.addConsole("input", cmdToRun);

    try {

      const res = eval(cmdToRun);
      let output = String(res);
      if (typeof res === "object" && res !== null) {
        try {
          output = JSON.stringify(res, null, 2);
        } catch (e) {
          output = Object.prototype.toString.call(res);
        }
      }
      if (output === undefined) output = "undefined";
      loggerStore.addConsole("output", output);
    } catch (e: any) {
      loggerStore.addConsole("error", e.message || String(e));
    }
  };

  const handleInputChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const val = e.target.value;
    setInputCmd(val);
    if (val.startsWith("\\")) {
      setShowPresets(true);
    } else {
      setShowPresets(false);
    }
  };

  const applyPreset = (preset: PresetCommand, runNow: boolean) => {
    if (runNow) {
      runConsole(preset.cmd);
    } else {
      setInputCmd(preset.cmd);
      setShowPresets(false);
    }
  };

  const clearInput = () => {
    setInputCmd("");
    setShowPresets(false);
  };

  const copyConsoleHistory = () => {
    const text = consoleHistory
      .map(
        (entry) =>
          `[${new Date(entry.timestamp).toLocaleTimeString()}] ${entry.type.toUpperCase()}: ${entry.content}`,
      )
      .join("\n");

    navigator.clipboard.writeText(text);
    setConsoleCopied(true);
    setTimeout(() => setConsoleCopied(false), 2000);
  };

  const downloadConsoleOutput = () => {
    const text = consoleHistory
      .map(
        (entry) =>
          `[${new Date(entry.timestamp).toLocaleTimeString()}] ${entry.type.toUpperCase()}: ${entry.content}`,
      )
      .join("\n");

    const blob = new Blob([text], { type: "text/plain" });
    const url = URL.createObjectURL(blob);
    const a = document.createElement("a");
    a.href = url;
    a.download = `console-history-${Date.now()}.txt`;
    document.body.appendChild(a);
    a.click();
    document.body.removeChild(a);
    URL.revokeObjectURL(url);
  };

  return (
    <div className="flex flex-col h-full relative">
      <div className="flex-1 overflow-y-auto p-4 bg-slate-900 custom-scrollbar flex flex-col gap-3">
        {consoleHistory.length === 0 && (
          <div className="text-slate-600 italic mt-2 opacity-50 select-none">
            {t.console.resultPlaceholder}
          </div>
        )}

        {consoleHistory.map((entry) => (
          <div
            key={entry.id}
            className="group animate-in fade-in slide-in-from-left-2 duration-200"
          >
            {entry.type === "input" ? (
              <div className="flex gap-2 items-start text-indigo-400 font-bold">
                <ChevronRight size={14} className="mt-0.5 shrink-0" />
                <span className="whitespace-pre-wrap break-all">
                  {entry.content}
                </span>
              </div>
            ) : entry.type === "error" ? (
              <div className="pl-5 text-red-400 bg-red-900/10 p-2 rounded border-l-2 border-red-500 whitespace-pre-wrap break-all relative">
                <TriangleAlert
                  size={12}
                  className="absolute left-1 top-2.5 opacity-50"
                />
                {entry.content}
              </div>
            ) : (
              <div className="pl-5 text-slate-300 relative">
                <span className="absolute left-0 top-1 text-slate-600 text-[10px] select-none">
                  &lt;
                </span>
                <pre className="whitespace-pre-wrap break-all font-mono text-emerald-400/90 selection:bg-emerald-900/50">
                  {entry.content}
                </pre>
              </div>
            )}
          </div>
        ))}
        <div ref={consoleEndRef} />
      </div>

      <div className="absolute top-2 right-2 flex gap-1">
        <button
          onClick={copyConsoleHistory}
          className="p-1.5 bg-slate-800/80 text-slate-400 hover:text-white hover:bg-slate-700 border border-slate-700 rounded backdrop-blur-sm transition-colors"
          title={t.console.copy}
        >
          {consoleCopied ? (
            <Check size={12} className="text-green-400" />
          ) : (
            <Copy size={12} />
          )}
        </button>
        <button
          onClick={downloadConsoleOutput}
          className="p-1.5 bg-slate-800/80 text-slate-400 hover:text-white hover:bg-slate-700 border border-slate-700 rounded backdrop-blur-sm transition-colors"
          title={t.console.download}
        >
          <Download size={12} />
        </button>
        <button
          onClick={() => loggerStore.clearConsole()}
          className="p-1.5 bg-slate-800/80 text-slate-400 hover:text-red-400 hover:bg-slate-700 border border-slate-700 rounded backdrop-blur-sm transition-colors"
          title={t.console.clear}
        >
          <Trash2 size={12} />
        </button>
      </div>

      {showPresets && (
        <div className="absolute bottom-[50px] left-2 right-2 bg-slate-800 border border-slate-700 rounded-lg shadow-xl z-10 animate-in slide-in-from-bottom-2 fade-in duration-200 flex flex-col overflow-hidden max-h-60">
          <div className="px-3 py-2 bg-slate-900/50 border-b border-slate-700 text-[10px] text-slate-400 font-medium uppercase tracking-wider backdrop-blur-sm shrink-0">
            {t.console.quickCommands}
          </div>
          <div className="overflow-y-auto">
            {PRESET_COMMANDS.map((preset, idx) => (
              <div
                key={idx}
                className="flex items-center justify-between p-2 hover:bg-slate-700/50 transition-colors group cursor-pointer"
                onClick={() => applyPreset(preset, false)}
              >
                <div className="flex items-center gap-3 overflow-hidden">
                  <div className="p-1.5 bg-slate-700 text-indigo-400 rounded group-hover:bg-indigo-900/30 group-hover:text-indigo-300 transition-colors">
                    <preset.icon size={14} />
                  </div>
                  <div className="flex flex-col min-w-0">
                    <span className="text-slate-200 font-medium truncate">
                      {(t.console as any).presets?.[preset.id]?.label ||
                        preset.id}
                    </span>
                    <span className="text-[10px] text-slate-500 truncate">
                      {(t.console as any).presets?.[preset.id]?.desc || ""}
                    </span>
                  </div>
                </div>
                <button
                  onClick={(e) => {
                    e.stopPropagation();
                    applyPreset(preset, true);
                  }}
                  className="p-1.5 text-slate-400 hover:text-green-400 hover:bg-slate-600 rounded transition-colors"
                  title={t.console.run}
                >
                  <Zap size={14} fill="currentColor" />
                </button>
              </div>
            ))}
          </div>
        </div>
      )}

      <div className="p-2 bg-slate-800 flex gap-2 shrink-0 relative z-20 items-center border-t border-slate-700">
        <div className="flex items-center text-slate-400 pl-2">
          <span className="font-bold text-lg">&gt;</span>
        </div>
        <div className="flex-1 relative flex items-center gap-2">
          <button
            onClick={() => setShowPresets(!showPresets)}
            className={`p-1.5 rounded hover:bg-slate-700 transition-colors ${showPresets ? "text-indigo-400 bg-indigo-900/30" : "text-slate-500"}`}
            title="Quick Commands"
          >
            <Command size={14} />
          </button>
          <div className="flex-1 relative flex items-center">
            <input
              type="text"
              value={inputCmd}
              onChange={handleInputChange}
              onKeyDown={(e) => e.key === "Enter" && runConsole()}
              placeholder={t.console.placeholder}
              className="w-full bg-transparent border-none outline-none text-white font-mono text-sm placeholder:text-slate-600 pr-8"
              autoFocus
              autoComplete="off"
            />
            {inputCmd && (
              <button
                onClick={clearInput}
                className="absolute right-0 p-1 text-slate-500 hover:text-slate-300 transition-colors"
                title={t.console.clearInput}
              >
                <X size={14} />
              </button>
            )}
          </div>
        </div>
        <button
          onClick={() => runConsole()}
          className="px-3 bg-indigo-600 hover:bg-indigo-500 text-white rounded flex items-center justify-center self-stretch shadow-sm active:scale-95 transition-transform"
        >
          <Play size={14} fill="currentColor" />
        </button>
      </div>
    </div>
  );
};

import React, { useState } from "react";

export const InspectorView: React.FC = () => {
  const [inspectorObj, setInspectorObj] = useState("navigator");

  const getInspectData = (key: string) => {
    let target: any = {};
    if (key === "navigator") target = navigator;
    else if (key === "screen") target = screen;
    else if (key === "location") target = location;
    else if (key === "performance") target = performance;
    else if (key === "document") target = document;

    const result: Record<string, any> = {};
    for (const k in target) {
      try {
        const val = target[k];
        if (typeof val !== "function") {
          result[k] = val;
        }
      } catch (e) {}
    }
    if (key === "navigator") {
      // @ts-ignore
      if ((navigator as any).userAgentData)
        result["userAgentData"] = (navigator as any).userAgentData;
      if ((navigator as any).connection)
        result["connection"] = (navigator as any).connection;
      // @ts-ignore
      if ((navigator as any).deviceMemory)
        result["deviceMemory"] = (navigator as any).deviceMemory;
    }

    return JSON.stringify(result, null, 2);
  };

  return (
    <div className="flex flex-col h-full">
      <div className="p-2 bg-slate-800 border-b border-slate-700 flex gap-2 shrink-0 overflow-x-auto">
        {["navigator", "screen", "location", "performance"].map((obj) => (
          <button
            key={obj}
            onClick={() => setInspectorObj(obj)}
            className={`px-3 py-1 rounded text-[10px] uppercase font-bold transition-colors whitespace-nowrap ${inspectorObj === obj ? "bg-indigo-600 text-white" : "bg-slate-700 text-slate-400 hover:bg-slate-600"}`}
          >
            {obj}
          </button>
        ))}
      </div>
      <div className="flex-1 overflow-y-auto p-4 scrollbar-thin scrollbar-thumb-slate-700 bg-slate-900">
        <pre className="text-blue-300 whitespace-pre-wrap break-all">
          {getInspectData(inspectorObj)}
        </pre>
      </div>
    </div>
  );
};

import React, { Component, ErrorInfo, ReactNode } from "react";
import {
  AlertTriangle,
  RefreshCw,
  ChevronDown,
  ChevronUp,
  Copy,
  BookOpen,
  Bug,
  Trash2,
  Home,
  Monitor,
} from "lucide-react";
import { translations } from "../../utils/i18n";
import { Language } from "../../utils/i18n/types";
import { loggerStore } from "../../utils/loggerStore";

interface Props {
  children: ReactNode;
  fallback?: ReactNode;
  name?: string;
}

interface State {
  hasError: boolean;
  error: Error | null;
  errorInfo: ErrorInfo | null;
  showDetails: boolean;
  copied: boolean;
}

export class ErrorBoundary extends Component<Props, State> {
  public state: State = {
    hasError: false,
    error: null,
    errorInfo: null,
    showDetails: false,
    copied: false,
  };

  private handleGlobalError = (event: ErrorEvent) => {
    if (this.props.name === "RootApp" && !this.state.hasError) {
      if (event.message && (event.message.includes("VConsole") || event.message.includes("vconsole"))) return;
      this.setState({
        hasError: true,
        error: event.error || new Error(event.message),
        errorInfo: { componentStack: "Captured by Window Error Listener" },
      });
    }
  };

  private handleGlobalPromise = (event: PromiseRejectionEvent) => {
    if (this.props.name === "RootApp" && !this.state.hasError) {
      const msg = event.reason instanceof Error ? event.reason.message : String(event.reason);
      if (msg.includes("VConsole") || msg.includes("vconsole")) return;
      this.setState({
        hasError: true,
        error: event.reason instanceof Error ? event.reason : new Error(msg),
        errorInfo: { componentStack: "Captured by Window Unhandled Rejection Listener" },
      });
    }
  };

  public componentDidMount() {
    if (this.props.name === "RootApp") {
      window.addEventListener("error", this.handleGlobalError);
      window.addEventListener("unhandledrejection", this.handleGlobalPromise);
    }
  }

  public componentWillUnmount() {
    if (this.props.name === "RootApp") {
      window.removeEventListener("error", this.handleGlobalError);
      window.removeEventListener("unhandledrejection", this.handleGlobalPromise);
    }
  }

  public static getDerivedStateFromError(error: Error): Partial<State> {
    return { hasError: true, error };
  }

  public componentDidCatch(error: Error, errorInfo: ErrorInfo) {
    this.setState({ errorInfo });
    const errorMsg = `Uncaught error in component [${this.props.name || "Unknown"}]: ${error.message}\n${errorInfo.componentStack}`;
    console.error(errorMsg);
    // Explicitly add to loggerStore so it triggers our global console interception safely
    loggerStore.addConsole("error", errorMsg);
  }

  public handleRetry = () => {
    this.setState({
      hasError: false,
      error: null,
      errorInfo: null,
      showDetails: false,
      copied: false,
    });
  };

  public handleCopy = () => {
    const { error, errorInfo } = this.state;
    const ua = navigator.userAgent;
    const url = window.location.href;
    const timestamp = new Date().toISOString();

    const text = `--- Context Metadata ---
Time: ${timestamp}
URL: ${url}
User Agent: ${ua}

--- Error Details ---
Component: ${this.props.name || "Unknown"}
Error: ${error?.message}

--- Error Stack ---
${error?.stack || "No stack trace available."}

--- Component Stack ---
${errorInfo?.componentStack || "No component stack available."}`;

    try {
      navigator.clipboard.writeText(text);
      this.setState({ copied: true });
      setTimeout(() => this.setState({ copied: false }), 2000);
    } catch (e) {}
  };

  public handleClearCache = () => {
    if (
      window.confirm(
        "Are you sure you want to clear cache and reload? This will reset all your settings.",
      )
    ) {
      localStorage.clear();
      sessionStorage.clear();
      window.location.reload();
    }
  };

  public handleHome = () => {
    window.dispatchEvent(new Event("close-all-modals"));
    this.setState({
      hasError: false,
      error: null,
      errorInfo: null,
      showDetails: false,
      copied: false,
    });
  };

  public handleReload = () => {
    window.location.reload();
  };

  private getAnalysis(error: Error | null, t: any) {
    if (!error) return t.analysis_no_error || "No error object available.";
    const msg = error.message.toLowerCase();
    if (
      msg.includes("cannot read properties of undefined") ||
      msg.includes("cannot read properties of null") ||
      msg.includes("reading 'usestate'")
    ) {
      return (
        t.analysis_null_reference ||
        "Possible null reference error. Check if data is loaded before rendering."
      );
    }
    if (msg.includes("is not a function")) {
      return (
        t.analysis_function_call ||
        "Function call fail. Check if the callback/method exists and is bound correctly."
      );
    }
    if (
      msg.includes("invalid hook call") ||
      msg.includes("reading 'usestate'")
    ) {
      return (
        t.analysis_invalid_hook ||
        "React Hook issue. Hooks must be called inside a functional component body."
      );
    }
    if (msg.includes("network") || msg.includes("fetch")) {
      return (
        t.analysis_network ||
        "Network error. Check your internet connection or API endpoint status."
      );
    }
    if (msg.includes("unexpected token") || msg.includes("json")) {
      return (
        t.analysis_json ||
        "JSON parsing error. Received unexpected data format from the server."
      );
    }
    return (
      t.analysis_unexpected ||
      "Unexpected runtime error. Please review the stack trace below."
    );
  }

  private getTranslation() {
    const defaultLang = "en";
    let lang = defaultLang;
    try {
      const stored = localStorage.getItem("language");
      if (stored && translations[stored as Language]) {
        lang = stored;
      }
    } catch (e) {}

    // Fallback to english if not found
    return (
      (translations[lang as Language] as any)?.common?.error_boundary || {
        title: "Component Crashed",
        message: "An unexpected error occurred rendering this module.",
        retry: "Try Again",
        unknown_component: "Unknown Component",
      }
    );
  }

  public render() {
    if (this.state.hasError) {
      if (this.props.fallback) {
        return this.props.fallback;
      }

      const t = this.getTranslation();
      const analysisMsg = this.getAnalysis(this.state.error, t);

      return (
        <div style={{
          position: 'fixed', inset: 0, zIndex: 9999, backgroundColor: 'rgba(15, 23, 42, 0.8)', padding: '20px', display: 'flex', alignItems: 'flex-start', justifyContent: 'center', overflowY: 'auto'
        }} className="fixed inset-0 z-[9999] bg-slate-900/60 backdrop-blur-sm p-4 md:p-8 flex items-start justify-center overflow-y-auto">
          <div style={{
            backgroundColor: '#fffcfc', border: '1px solid #fca5a5', borderRadius: '12px', padding: '24px', display: 'flex', flexDirection: 'column', textAlign: 'left', boxShadow: '0 25px 50px -12px rgba(0, 0, 0, 0.25)', width: '100%', maxWidth: '896px', fontFamily: 'sans-serif', marginTop: '40px', color: '#1e293b'
          }} className="p-6 bg-red-50 dark:bg-slate-900 border border-red-200 dark:border-red-900/60 rounded-xl flex flex-col text-left shadow-2xl w-full max-w-4xl font-sans relative backdrop-blur-md mt-10 md:mt-20">
            <div className="flex items-center gap-3 mb-4" style={{ display: 'flex', alignItems: 'center', gap: '12px', marginBottom: '16px' }}>
              <div className="p-2.5 bg-red-100 dark:bg-red-900/30 rounded-lg text-red-600 dark:text-red-400 shrink-0">
                <AlertTriangle size={24} />
              </div>
              <div>
                <h3 className="text-lg font-bold text-red-800 dark:text-red-300">
                  {t.title}{" "}
                  <span className="text-red-500 font-normal text-sm opacity-70">
                    {t.component_in || "in"}{" "}
                    {this.props.name || t.unknown_component}
                  </span>
                </h3>
                <p className="text-sm text-red-600 dark:text-red-400 font-medium">
                  {this.state.error?.message || t.message}
                </p>
              </div>
            </div>

            <div className="mb-4 bg-orange-50 dark:bg-orange-900/10 border border-orange-200 dark:border-orange-900/30 rounded p-3 text-sm text-orange-800 dark:text-orange-300 flex gap-2 items-start">
              <BookOpen size={16} className="shrink-0 mt-0.5" />
              <div>
                <span className="font-bold block mb-1">
                  {t.preliminary_analysis || "Preliminary Analysis:"}
                </span>
                {analysisMsg}
              </div>
            </div>

            <div className="flex items-center gap-3 flex-wrap mb-4">
              <button
                onClick={this.handleRetry}
                className="flex items-center gap-2 px-4 py-2 bg-red-600 hover:bg-red-700 text-white rounded-lg text-sm font-medium transition-colors shadow-sm"
              >
                <RefreshCw size={16} />
                {t.retry}
              </button>

              <button
                onClick={this.handleClearCache}
                className="flex items-center gap-2 px-4 py-2 bg-orange-600 hover:bg-orange-700 text-white rounded-lg text-sm font-medium transition-colors shadow-sm"
              >
                <Trash2 size={16} />
                {t.clear_cache || "Clear Cache & Reload"}
              </button>

              <button
                onClick={this.handleHome}
                className="flex items-center gap-2 px-4 py-2 bg-slate-600 hover:bg-slate-700 text-white rounded-lg text-sm font-medium transition-colors shadow-sm"
              >
                <Home size={16} />
                {t.home || "Return Home"}
              </button>

              <button
                onClick={this.handleReload}
                className="flex items-center gap-2 px-4 py-2 bg-blue-600 hover:bg-blue-700 text-white rounded-lg text-sm font-medium transition-colors shadow-sm"
              >
                <RefreshCw size={16} />
                {t.reload_page || "Reload Page"}
              </button>

              <button
                onClick={() =>
                  this.setState((s) => ({ showDetails: !s.showDetails }))
                }
                className="flex items-center gap-2 px-3 py-2 bg-red-100 hover:bg-red-200 dark:bg-red-900/30 dark:hover:bg-red-900/50 text-red-700 dark:text-red-300 rounded-lg text-sm font-medium transition-colors"
              >
                {this.state.showDetails ? (
                  <ChevronUp size={16} />
                ) : (
                  <ChevronDown size={16} />
                )}
                {this.state.showDetails
                  ? t.hide_stack_trace || "Hide Stack Trace"
                  : t.show_stack_trace || "View Stack Trace"}
              </button>

              {this.state.showDetails && (
                <button
                  onClick={this.handleCopy}
                  className="flex items-center gap-2 px-3 py-2 bg-white dark:bg-slate-800 hover:bg-slate-50 dark:hover:bg-slate-700 text-slate-700 dark:text-slate-300 border border-slate-200 dark:border-slate-700 rounded-lg text-sm font-medium transition-colors ml-auto"
                >
                  {this.state.copied ? (
                    <Copy size={16} className="text-green-500" />
                  ) : (
                    <Copy size={16} />
                  )}
                  {this.state.copied
                    ? t.copied || "Copied!"
                    : t.copy_error_details || "Copy Error Details"}
                </button>
              )}
            </div>

            {this.state.showDetails && (
              <div className="mt-2 bg-slate-100 dark:bg-[#0f172a] rounded-lg p-4 overflow-x-auto text-xs text-red-900 dark:text-red-300 font-mono text-left w-full shadow-inner border border-red-200 dark:border-red-900">
                <div className="text-slate-500 dark:text-slate-400 mb-2 border-b border-red-200 dark:border-red-900/50 pb-2 flex items-center gap-1 font-bold font-sans">
                  <Monitor size={14} />{" "}
                  {t.context_metadata || "Environment Context"}
                </div>
                <div className="grid grid-cols-1 md:grid-cols-2 gap-3 mb-6 bg-white/50 dark:bg-black/20 p-3 rounded border border-red-100 dark:border-red-900/30">
                  <div className="flex flex-col gap-0.5">
                    <span className="text-[10px] text-slate-500 uppercase tracking-wider">
                      {t.time || "Timestamp"}
                    </span>
                    <span className="text-slate-700 dark:text-slate-300 select-all">
                      {new Date().toISOString()}
                    </span>
                  </div>
                  <div className="flex flex-col gap-0.5">
                    <span className="text-[10px] text-slate-500 uppercase tracking-wider">
                      {t.url || "Current URL"}
                    </span>
                    <span className="text-slate-700 dark:text-slate-300 break-all select-all">
                      {window.location.href}
                    </span>
                  </div>
                  <div className="col-span-1 md:col-span-2 flex flex-col gap-0.5">
                    <span className="text-[10px] text-slate-500 uppercase tracking-wider">
                      {t.user_agent || "User Agent"}
                    </span>
                    <span className="text-slate-600 dark:text-slate-400 break-words select-all">
                      {navigator.userAgent}
                    </span>
                  </div>
                </div>

                <div className="text-slate-500 dark:text-slate-400 mb-2 border-b border-red-200 dark:border-red-900/50 pb-2 flex items-center gap-1 font-bold font-sans">
                  <Bug size={14} /> {t.error_stack || "Error Stack"}
                </div>
                <div className="whitespace-pre-wrap break-all mb-6 bg-white/50 dark:bg-black/20 p-3 rounded border border-red-100 dark:border-red-900/30">
                  {this.state.error?.stack
                    ? this.state.error.stack.split("\n").map((line, i) => {
                        if (line.trim().startsWith("at ")) {
                          const match = line.match(
                            /(at\s+)([A-Za-z0-9_$.<>]+)(\s+\(?)/,
                          );
                          if (match) {
                            return (
                              <div
                                key={i}
                                className="text-slate-700 dark:text-slate-300"
                              >
                                <span className="text-slate-500 dark:text-slate-500">
                                  {match[1]}
                                </span>
                                <span className="text-emerald-700 dark:text-yellow-300 font-semibold">
                                  {match[2]}
                                </span>
                                <span>
                                  {line.substring(match[0].length - 1)}
                                </span>
                              </div>
                            );
                          }
                          return (
                            <div
                              key={i}
                              className="text-slate-700 dark:text-slate-300"
                            >
                              {line}
                            </div>
                          );
                        }
                        return (
                          <div
                            key={i}
                            className="text-red-600 dark:text-red-300 font-bold"
                          >
                            {line}
                          </div>
                        );
                      })
                    : t.no_stack_trace || "No stack trace available."}
                </div>
                <div className="text-slate-500 dark:text-slate-400 mb-2 border-b border-red-200 dark:border-red-900/50 pb-2 flex items-center gap-1 font-bold font-sans mt-6">
                  <AlertTriangle size={14} />{" "}
                  {t.component_stack || "React Component Stack"}
                </div>
                <div className="whitespace-pre-wrap break-all bg-white/50 dark:bg-black/20 p-3 rounded border border-red-100 dark:border-red-900/30 text-orange-600 dark:text-orange-300">
                  {this.state.errorInfo?.componentStack
                    ? this.state.errorInfo.componentStack
                        .split("\n")
                        .map((line, i) => {
                          if (!line.trim()) return null;
                          const isCurrent =
                            this.props.name && line.includes(this.props.name);
                          return (
                            <div
                              key={i}
                              className={`py-0.5 ${isCurrent ? "bg-indigo-100 dark:bg-indigo-900/40 text-indigo-700 dark:text-indigo-300 font-bold px-2 rounded-sm border-l-2 border-indigo-500 my-1" : ""}`}
                            >
                              {line}
                            </div>
                          );
                        })
                    : t.no_component_stack || "No component stack available."}
                </div>
              </div>
            )}
          </div>
        </div>
      );
    }

    return this.props.children;
  }
}

import React, { useState, useRef, useEffect } from 'react';
import { createPortal } from 'react-dom';
import { X, Maximize2, Move, Minus } from 'lucide-react';

interface FloatingWindowProps {
    title: string;
    onClose: () => void; // Docks back
    children: React.ReactNode;
    initialWidth?: number;
    initialHeight?: number;
}

type DragMode = 'move' | 'resize-nw' | 'resize-ne' | 'resize-sw' | 'resize-se' | null;

export const FloatingWindow: React.FC<FloatingWindowProps> = ({ 
    title, 
    onClose, 
    children, 
    initialWidth = 600, 
    initialHeight = 400 
}) => {
    // Initial position centered
    const [rect, setRect] = useState({
        x: Math.max(50, window.innerWidth / 2 - initialWidth / 2),
        y: Math.max(50, window.innerHeight / 2 - initialHeight / 2),
        w: initialWidth,
        h: initialHeight
    });

    // Use Refs for values needed inside event listeners to avoid closure staleness
    // and to prevent re-binding listeners on every render.
    const rectRef = useRef(rect);
    const dragModeRef = useRef<DragMode>(null);
    const startPosRef = useRef({ x: 0, y: 0 });
    const startRectRef = useRef({ x: 0, y: 0, w: 0, h: 0 });

    // Sync ref with state
    useEffect(() => {
        rectRef.current = rect;
    }, [rect]);

    const handlePointerDown = (e: React.PointerEvent, mode: DragMode) => {
        e.preventDefault();
        e.stopPropagation();

        dragModeRef.current = mode;
        startPosRef.current = { x: e.clientX, y: e.clientY };
        startRectRef.current = { ...rectRef.current };

        const target = e.currentTarget;
        target.setPointerCapture(e.pointerId);

        document.body.style.userSelect = 'none';
        document.body.style.cursor = mode === 'move' ? 'move' : (mode?.includes('nw') || mode?.includes('se') ? 'nwse-resize' : 'nesw-resize');

        const handleMove = (ev: PointerEvent) => {
            if (!dragModeRef.current) return;
            ev.preventDefault();

            const dx = ev.clientX - startPosRef.current.x;
            const dy = ev.clientY - startPosRef.current.y;
            const s = startRectRef.current;
            const currentMode = dragModeRef.current;

            const newRect = { ...s };
            const minSize = 300;

            if (currentMode === 'move') {
                newRect.x = s.x + dx;
                newRect.y = s.y + dy;
            } else {
                if (currentMode.includes('e')) {
                    newRect.w = Math.max(minSize, s.w + dx);
                }
                if (currentMode.includes('s')) {
                    newRect.h = Math.max(minSize, s.h + dy);
                }
                if (currentMode.includes('w')) {
                    const newW = Math.max(minSize, s.w - dx);
                    newRect.w = newW;
                    newRect.x = s.x + (s.w - newW);
                }
                if (currentMode.includes('n')) {
                    const newH = Math.max(minSize, s.h - dy);
                    newRect.h = newH;
                    newRect.y = s.y + (s.h - newH);
                }
            }

            setRect(newRect);
        };

        const handleUp = (ev: PointerEvent) => {
            target.releasePointerCapture(ev.pointerId);
            dragModeRef.current = null;
            document.body.style.userSelect = '';
            document.body.style.cursor = '';
            window.removeEventListener('pointermove', handleMove as EventListener);
            window.removeEventListener('pointerup', handleUp as EventListener);
            window.removeEventListener('pointercancel', handleUp as EventListener);
        };

        window.addEventListener('pointermove', handleMove as EventListener, { passive: false });
        window.addEventListener('pointerup', handleUp as EventListener);
        window.addEventListener('pointercancel', handleUp as EventListener);
    };

    return createPortal(
        <div 
            contentEditable={false}
            className="fixed z-[9999] bg-slate-900/95 backdrop-blur-md border border-slate-700 rounded-lg shadow-2xl flex flex-col overflow-hidden ring-1 ring-white/10 transition-shadow duration-200"
            style={{
                left: rect.x,
                top: rect.y,
                width: rect.w,
                height: rect.h,
                boxShadow: '0 20px 50px -12px rgba(0, 0, 0, 0.5)'
            }}
        >
            {/* Header / Drag Handle */}
            <div 
                className="h-10 bg-slate-800 border-b border-slate-700 flex items-center justify-between px-3 cursor-move touch-none select-none shrink-0 group"
                onPointerDown={(e) => handlePointerDown(e, 'move')}
            >
                <div className="flex items-center gap-2 text-slate-300">
                    <Move size={14} className="opacity-50 group-hover:opacity-100 transition-opacity" />
                    <span className="text-xs font-bold tracking-wide uppercase">{title}</span>
                </div>
                <div className="flex items-center gap-1" onPointerDown={(e) => e.stopPropagation()}>
                    <button 
                        onClick={onClose}
                        className="p-1.5 hover:bg-slate-700 rounded text-slate-400 hover:text-white transition-colors"
                        title="Dock back to settings"
                    >
                        <Minus size={14} />
                    </button>
                </div>
            </div>

            {/* Content */}
            <div className="flex-1 overflow-hidden relative bg-slate-950 flex flex-col">
                {children}
            </div>

            {/* Resize Handles */}
            {/* Corners */}
            <div 
                className="absolute top-0 left-0 w-4 h-4 cursor-nwse-resize touch-none z-50 opacity-0 hover:opacity-100 bg-white/10 transition-opacity rounded-br"
                onPointerDown={(e) => handlePointerDown(e, 'resize-nw')}
            />
            <div 
                className="absolute top-0 right-0 w-4 h-4 cursor-nesw-resize touch-none z-50 opacity-0 hover:opacity-100 bg-white/10 transition-opacity rounded-bl"
                onPointerDown={(e) => handlePointerDown(e, 'resize-ne')}
            />
            <div 
                className="absolute bottom-0 left-0 w-4 h-4 cursor-nesw-resize touch-none z-50 opacity-0 hover:opacity-100 bg-white/10 transition-opacity rounded-tr"
                onPointerDown={(e) => handlePointerDown(e, 'resize-sw')}
            />

            {/* Visible Resize Handle Bottom Right */}
            <div 
                className="absolute bottom-0 right-0 w-5 h-5 cursor-nwse-resize touch-none z-50 flex items-end justify-end p-1 hover:bg-white/5"
                onPointerDown={(e) => handlePointerDown(e, 'resize-se')}
            >
                <svg width="8" height="8" viewBox="0 0 8 8" fill="none" className="text-slate-500">
                    <path d="M8 8H0L8 0V8Z" fill="currentColor" opacity="0.5"/>
                </svg>
            </div>
        </div>,
        document.body
    );
};

import React, { useEffect, useState, useRef } from 'react';
import { createPortal } from 'react-dom';
import { X } from 'lucide-react';

export interface ModalProps {
  isOpen?: boolean; // If controlled externally (optional, usually we mount/unmount)
  onClose: () => void;
  title: string;
  icon?: React.ReactNode;
  children: React.ReactNode | ((args: { close: () => void }) => React.ReactNode);
  size?: 'sm' | 'md' | 'lg' | 'xl' | '2xl' | '3xl' | '4xl' | '5xl' | 'full';
  className?: string;
  noPadding?: boolean; // If true, removes default padding from body (useful for custom layouts like Settings/Camera)
  fullHeight?: boolean; // If true, forces a fixed large height (good for tools/settings)
  disableHeaderBlur?: boolean; // If true, disables the blurred header effect
}

export const Modal: React.FC<ModalProps> = ({ 
  onClose, 
  title, 
  icon, 
  children, 
  size = 'md',
  className = '',
  noPadding = false,
  fullHeight = false,
  disableHeaderBlur = false
}) => {
  const [isVisible, setIsVisible] = useState(false);
  const [isClosing, setIsClosing] = useState(false);
  const modalRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    // Trigger entry animation
    const timer = requestAnimationFrame(() => {
        setIsVisible(true);
    });

    // Lock body scroll and compensate for scrollbar to avoid CLS
    const scrollbarWidth = window.innerWidth - document.documentElement.clientWidth;
    if (scrollbarWidth > 0) {
        document.body.style.paddingRight = `${scrollbarWidth}px`;
    }
    document.body.style.overflow = 'hidden';

    // Focus management
    if (modalRef.current) {
        modalRef.current.focus();
    }

    return () => {
        cancelAnimationFrame(timer);
        document.body.style.overflow = '';
        document.body.style.paddingRight = '';
    };
  }, []);

  const handleClose = () => {
    if (isClosing) return;
    setIsClosing(true);
    // Wait for animation to finish
    setTimeout(() => {
      onClose();
    }, 300);
  };

  const handleKeyDown = (e: React.KeyboardEvent) => {
      if (e.key === 'Escape') handleClose();
  };

  const sizes = {
    sm: 'max-w-sm',
    md: 'max-w-lg',
    lg: 'max-w-2xl',
    xl: 'max-w-3xl',
    '2xl': 'max-w-4xl',
    '3xl': 'max-w-5xl',
    '4xl': 'max-w-6xl',
    '5xl': 'max-w-7xl',
    full: 'max-w-full m-4',
  };

  const heightClass = fullHeight ? 'h-[85vh] md:h-[90vh]' : 'max-h-[85vh]';

  // Support Render Props to pass the animated close function to children
  const content = typeof children === 'function' ? children({ close: handleClose }) : children;

  // Header Style Configuration
  // For standard modals (noPadding=false), we use absolute positioning to let content scroll behind.
  // For complex layout modals (noPadding=true), we use relative positioning to ensure layout stability, but still apply blur.
  const headerPositionClass = noPadding ? 'relative' : 'absolute top-0 left-0 w-full';

  // Content Container Style
  // If absolute header, we need padding-top on the scroll container.
  // We use h-full to fill the modal.
  const contentContainerClass = noPadding 
    ? 'flex-1 overflow-hidden flex flex-col relative' // Complex layout: Flex based
    : 'h-full overflow-y-auto custom-scrollbar pt-20 px-6 pb-6 bg-slate-50 dark:bg-slate-900'; // Standard: Scrollable with top padding for header

  const animationStyle = localStorage.getItem('animationStyle') || 'slide-up';

  return createPortal(
    <div 
      className={`fixed inset-0 z-50 flex items-center justify-center p-4 bg-slate-900/60 backdrop-blur-[2px] transition-all duration-300 ease-out ${
        isClosing ? 'opacity-0' : 'opacity-100'
      }`}
      onClick={handleClose}
      onKeyDown={handleKeyDown}
      tabIndex={-1}
      role="dialog"
      aria-modal="true"
    >
      <div 
        ref={modalRef}
        key={animationStyle}
        className={`
            bg-white dark:bg-slate-800 rounded-2xl shadow-2xl w-full flex flex-col overflow-hidden 
            outline-none border border-white/10 relative
            ${sizes[size]} 
            ${heightClass}
            ${isClosing ? 'opacity-0 scale-95 blur-sm translate-y-4 transition-all duration-300 ease-out' : ''}
            ${!isClosing ? (
                animationStyle === 'slide-up' ? 'anim-slide-up' : 
                animationStyle === 'fade' ? 'anim-fade' : 
                animationStyle === 'fly-in' ? 'anim-fly-in' : 
                animationStyle === 'zoom' ? 'anim-zoom' : 'anim-slide-up'
            ) : ''}
            ${className}
        `}
        onClick={(e) => e.stopPropagation()}
      >
        {/* Blur Header */}
        <div className={`
            px-6 py-4 flex justify-between items-center z-30 shrink-0
            ${disableHeaderBlur 
                ? 'bg-white dark:bg-slate-800 border-b border-slate-100 dark:border-slate-700' 
                : 'bg-white/80 dark:bg-slate-800/80 backdrop-blur-md border-b border-slate-200/60 dark:border-slate-700/60 supports-[backdrop-filter]:bg-white/60 supports-[backdrop-filter]:dark:bg-slate-800/60'
            }
            ${headerPositionClass}
        `}>
          <div className="flex items-center gap-3 overflow-hidden">
             {icon && (
                 <div className="text-indigo-600 dark:text-indigo-400 shrink-0">
                    {icon}
                 </div>
             )}
             <h2 className="text-xl font-bold text-slate-900 dark:text-slate-100 truncate tracking-tight">
                {title}
             </h2>
          </div>
          <button 
            onClick={handleClose}
            className="p-2 ml-4 hover:bg-slate-100 dark:hover:bg-slate-700/50 rounded-full transition-colors text-slate-500 dark:text-slate-400 focus:outline-none focus:ring-2 focus:ring-indigo-500/50 shrink-0"
            aria-label="Close"
          >
            <X size={20} />
          </button>
        </div>

        {/* Content Area */}
        <div className={contentContainerClass}>
            {content}
        </div>
      </div>
    </div>,
    document.body
  );
};

import React, { useEffect, useState } from 'react';
import { Cpu, Loader2 } from 'lucide-react';

export const ModalLoading: React.FC<{ initializingText?: string, loadingText?: string }> = ({ 
    initializingText = "Initializing", 
    loadingText = "Loading Module Resource" 
}) => {
  const [isVisible, setIsVisible] = useState(false);

  useEffect(() => {
    // Trigger animation frame to ensure the transition happens after mount
    // Using double RAF to ensure browser paint cycle has registered the initial state
    const timer = requestAnimationFrame(() => {
        requestAnimationFrame(() => {
            setIsVisible(true);
        });
    });
    return () => cancelAnimationFrame(timer);
  }, []);

  return (
    <div 
        className="fixed inset-0 z-[60] flex items-center justify-center p-4 bg-slate-900/60 backdrop-blur-[2px]"
    >
        <div 
            className={`
                relative bg-white/90 dark:bg-slate-900/90 p-8 rounded-2xl shadow-2xl 
                border border-white/20 dark:border-indigo-500/30 
                flex flex-col items-center gap-6 
                transform transition-all duration-500 cubic-bezier(0.34, 1.56, 0.64, 1)
                ${isVisible ? 'scale-100 translate-y-0' : 'scale-90 translate-y-8'}
            `}
        >
            {/* Background Glow Effect */}
            <div className="absolute inset-0 bg-indigo-500/5 dark:bg-indigo-500/10 blur-xl rounded-2xl pointer-events-none" />

            {/* Central Tech Spinner */}
            <div className="relative">
                {/* Outer Ring */}
                <div className="absolute inset-0 rounded-full border-2 border-indigo-100 dark:border-slate-700" />

                {/* Spinning Segment */}
                <div className="absolute inset-0 rounded-full border-t-2 border-indigo-500 animate-spin" />

                {/* Inner Pulsing Core */}
                <div className="relative z-10 w-16 h-16 bg-slate-50 dark:bg-slate-800 rounded-full flex items-center justify-center shadow-inner border border-slate-100 dark:border-slate-700">
                    <Cpu className="text-indigo-500 animate-pulse" size={28} />
                </div>

                {/* Satellite Particle */}
                <div className="absolute -inset-2 animate-[spin_3s_linear_infinite_reverse]">
                    <div className="w-2 h-2 bg-purple-500 rounded-full shadow-[0_0_8px_rgba(168,85,247,0.8)] absolute top-0 left-1/2 -translate-x-1/2" />
                </div>
            </div>

            {/* Text Content */}
            <div className="text-center space-y-2 relative z-10">
                <h3 className="text-lg font-bold text-slate-800 dark:text-white tracking-tight flex items-center justify-center gap-2">
                    {initializingText}
                    <span className="flex gap-1">
                        <span className="w-1 h-1 bg-indigo-500 rounded-full animate-bounce [animation-delay:-0.3s]"></span>
                        <span className="w-1 h-1 bg-indigo-500 rounded-full animate-bounce [animation-delay:-0.15s]"></span>
                        <span className="w-1 h-1 bg-indigo-500 rounded-full animate-bounce"></span>
                    </span>
                </h3>
                <p className="text-xs font-medium text-slate-500 dark:text-slate-400 font-mono uppercase tracking-widest">
                    {loadingText}
                </p>
            </div>

            {/* Bottom Progress Bar Decoration */}
            <div className="w-32 h-1 bg-slate-100 dark:bg-slate-800 rounded-full overflow-hidden">
                <div className="h-full bg-gradient-to-r from-indigo-500 via-purple-500 to-indigo-500 w-[200%] animate-[shimmer_2s_infinite_linear]" />
            </div>
        </div>
    </div>
  );
};

