import { useState, useEffect } from "react";
import { Language } from "../utils/i18n/index";
import { applyTheme, getSavedTheme, Theme } from "../appearance/theme";

export function useAppSettings() {
  const [lang, setLang] = useState<Language>(() => {
    const saved = localStorage.getItem("language");
    return (saved as Language) || "zh-CN";
  });

  const changeLang = (newLang: Language) => {
    setLang(newLang);
    localStorage.setItem("language", newLang);
    document.documentElement.lang = newLang;
  };

  const [theme, setTheme] = useState<Theme>("system");
  const [themeColor, setThemeColor] = useState<string>(
    () => localStorage.getItem("themeColor") || "indigo",
  );
  const [animationStyle, setAnimationStyle] = useState<string>(
    () => localStorage.getItem("animationStyle") || "slide-up",
  );
  const [initialAnimationStyle] = useState<string>(
    () => localStorage.getItem("animationStyle") || "slide-up",
  );
  const [simpleMode, setSimpleMode] = useState<boolean>(
    () => localStorage.getItem("simpleMode") === "true",
  );
  const [hideScrollbar, setHideScrollbar] = useState<boolean>(
    () => localStorage.getItem("hideScrollbar") === "true",
  );
  const [globalHideScrollbar, setGlobalHideScrollbar] = useState<boolean>(
    () => localStorage.getItem("globalHideScrollbar") === "true",
  );
  const [timeFormat, setTimeFormat] = useState<"12" | "24">(() => {
    const saved = localStorage.getItem("timeFormat");
    return saved === "12" || saved === "24" ? saved : "24";
  });
  const [disableBlur, setDisableBlur] = useState<boolean>(
    () => localStorage.getItem("disableBlur") === "true",
  );
  const [disableAnimations, setDisableAnimations] = useState<boolean>(
    () => localStorage.getItem("disableAnimations") === "true",
  );
  const [fastAnimations, setFastAnimations] = useState<boolean>(
    () => localStorage.getItem("fastAnimations") === "true",
  );
  const [collapseHeader, setCollapseHeader] = useState<boolean>(
    () => localStorage.getItem("collapseHeader") === "true",
  );
  const [enableUdp, setEnableUdp] = useState<boolean>(
    () => localStorage.getItem("enableUdp") === "true",
  );
  const [hiddenCards, setHiddenCards] = useState<string[]>(() => {
    try {
      const stored = localStorage.getItem("hiddenCards");
      return stored ? JSON.parse(stored) : [];
    } catch {
      return [];
    }
  });

  useEffect(() => {
    const savedTheme = getSavedTheme();
    setTheme(savedTheme);
    applyTheme(savedTheme);

    const mediaQuery = window.matchMedia("(prefers-color-scheme: dark)");
    const handleSystemThemeChange = () => {
      if (getSavedTheme() === "system") {
        applyTheme("system");
      }
    };

    if (mediaQuery.addEventListener) {
      mediaQuery.addEventListener("change", handleSystemThemeChange);
      return () =>
        mediaQuery.removeEventListener("change", handleSystemThemeChange);
    } else if (mediaQuery.addListener) {
      mediaQuery.addListener(handleSystemThemeChange);
      return () => mediaQuery.removeListener(handleSystemThemeChange);
    }
  }, []);

  useEffect(() => {
    const colors = [
      "theme-indigo",
      "theme-emerald",
      "theme-rose",
      "theme-amber",
      "theme-blue",
      "theme-violet",
      "theme-sky",
      "theme-cherry",
      "theme-ice",
    ];
    document.documentElement.classList.remove(...colors);
    if (themeColor !== "indigo") {
      document.documentElement.classList.add(`theme-${themeColor}`);
    }
  }, [themeColor]);

  useEffect(() => {
    if (hideScrollbar) {
      document.documentElement.classList.add("scrollbar-hide");
    } else {
      document.documentElement.classList.remove("scrollbar-hide");
    }
  }, [hideScrollbar]);

  useEffect(() => {
    if (globalHideScrollbar) {
      document.documentElement.classList.add("global-scrollbar-hide");
    } else {
      document.documentElement.classList.remove("global-scrollbar-hide");
    }
  }, [globalHideScrollbar]);

  useEffect(() => {
    if (disableBlur) {
      document.body.classList.add("no-blur");
    } else {
      document.body.classList.remove("no-blur");
    }
  }, [disableBlur]);

  useEffect(() => {
    if (disableAnimations) {
      document.body.classList.add("disable-animations");
      document.body.classList.remove("fast-animations");
      let style = document.getElementById("disable-animations-style");
      if (!style) {
        style = document.createElement("style");
        style.id = "disable-animations-style";
        style.innerHTML = `
                    *, *::before, *::after {
                        transition: none !important;
                        animation: none !important;
                        scroll-behavior: auto !important;
                    }
                `;
        document.head.appendChild(style);
      }
    } else {
      document.body.classList.remove("disable-animations");
      const style = document.getElementById("disable-animations-style");
      if (style) {
        style.remove();
      }

      if (fastAnimations) {
        document.body.classList.add("fast-animations");
      } else {
        document.body.classList.remove("fast-animations");
      }
    }
  }, [disableAnimations, fastAnimations]);

  const toggleTheme = () => {
    let newTheme: Theme;
    if (theme === "system") newTheme = "light";
    else if (theme === "light") newTheme = "dark";
    else newTheme = "system";

    const updateTheme = () => {
      setTheme(newTheme);
      applyTheme(newTheme);
    };

    if (!document.startViewTransition || disableAnimations) {
      updateTheme();
    } else {
      document.startViewTransition(() => {
        updateTheme();
      });
    }
  };

  const updateHiddenCards = (cards: string[]) => {
    setHiddenCards(cards);
    localStorage.setItem("hiddenCards", JSON.stringify(cards));

    const advancedCards = [
      "hardware",
      "fingerprint",
      "ai",
      "location",
      "storage",
      "permissions",
      "media_devices",
      "media_capabilities",
      "pwa",
      "features",
      "user_agent",
    ];
    const hasAllAdvanced = advancedCards.every((c) => cards.includes(c));
    if (simpleMode !== hasAllAdvanced) {
      setSimpleMode(hasAllAdvanced);
      localStorage.setItem("simpleMode", String(hasAllAdvanced));
    }
  };

  const toggleSimpleMode = (value: boolean) => {
    setSimpleMode(value);
    localStorage.setItem("simpleMode", String(value));

    const advancedCards = [
      "hardware",
      "fingerprint",
      "ai",
      "location",
      "storage",
      "permissions",
      "media_devices",
      "media_capabilities",
      "pwa",
      "features",
      "user_agent",
    ];
    if (value) {
      const newHidden = Array.from(new Set([...hiddenCards, ...advancedCards]));
      setHiddenCards(newHidden);
      localStorage.setItem("hiddenCards", JSON.stringify(newHidden));
    } else {
      const newHidden = hiddenCards.filter((c) => !advancedCards.includes(c));
      setHiddenCards(newHidden);
      localStorage.setItem("hiddenCards", JSON.stringify(newHidden));
    }
  };

  const updateThemeColor = (color: string) => {
    setThemeColor(color);
    localStorage.setItem("themeColor", color);
  };

  const updateAnimationStyle = (style: string) => {
    setAnimationStyle(style);
    localStorage.setItem("animationStyle", style);
  };

  const toggleHideScrollbar = (value: boolean) => {
    setHideScrollbar(value);
    localStorage.setItem("hideScrollbar", String(value));
  };

  const toggleGlobalHideScrollbar = (value: boolean) => {
    setGlobalHideScrollbar(value);
    localStorage.setItem("globalHideScrollbar", String(value));
  };

  const updateTimeFormat = (format: "12" | "24") => {
    setTimeFormat(format);
    localStorage.setItem("timeFormat", format);
  };

  const toggleDisableBlur = (value: boolean) => {
    setDisableBlur(value);
    localStorage.setItem("disableBlur", String(value));
  };

  const toggleDisableAnimations = (value: boolean) => {
    setDisableAnimations(value);
    localStorage.setItem("disableAnimations", String(value));
  };

  const toggleFastAnimations = (value: boolean) => {
    setFastAnimations(value);
    localStorage.setItem("fastAnimations", String(value));
  };

  const toggleCollapseHeader = (value: boolean) => {
    setCollapseHeader(value);
    localStorage.setItem("collapseHeader", String(value));
  };

  const toggleEnableUdp = (value: boolean) => {
    setEnableUdp(value);
    localStorage.setItem("enableUdp", String(value));
  };

  return {
    lang,
    changeLang,
    theme,
    toggleTheme,
    themeColor,
    updateThemeColor,
    animationStyle,
    updateAnimationStyle,
    initialAnimationStyle,
    simpleMode,
    toggleSimpleMode,
    hideScrollbar,
    toggleHideScrollbar,
    globalHideScrollbar,
    toggleGlobalHideScrollbar,
    timeFormat,
    updateTimeFormat,
    disableBlur,
    toggleDisableBlur,
    disableAnimations,
    toggleDisableAnimations,
    fastAnimations,
    toggleFastAnimations,
    collapseHeader,
    toggleCollapseHeader,
    enableUdp,
    toggleEnableUdp,
    hiddenCards,
    updateHiddenCards,
  };
}

import { useState, useEffect } from 'react';

export type AnomalyLevel = 'safe' | 'suspicious' | 'danger';
export type AnomalyCategory = 'trust' | 'normalcy';

export interface Anomaly {
    id: string;
    description: string;
    level: AnomalyLevel;
    category: AnomalyCategory;
}

export interface EnvironmentAssessment {
    isTrusted: boolean;
    trustScore: number;    // 0-100 (Based on tampering / bots)
    normalcyScore: number; // 0-100 (Based on system logic / layout / hardware consistency)
    trustLevel: AnomalyLevel;
    normalcyLevel: AnomalyLevel;
    anomalies: Anomaly[];
    isLoading: boolean;
}

export const useEnvironmentAssessment = (): EnvironmentAssessment => {
    const [assessment, setAssessment] = useState<EnvironmentAssessment>({
        isTrusted: true,
        trustScore: 100,
        normalcyScore: 100,
        trustLevel: 'safe',
        normalcyLevel: 'safe',
        anomalies: [],
        isLoading: true
    });

    useEffect(() => {
        const analyze = async () => {
            const anomalies: Anomaly[] = [];
            let trustScore = 100;
            let normalcyScore = 100;

            const addAnomaly = (id: string, description: string, level: AnomalyLevel, category: AnomalyCategory, scoreDeduction: number) => {
                anomalies.push({ id, description, level, category });
                if (category === 'trust') {
                    trustScore -= scoreDeduction;
                } else {
                    normalcyScore -= scoreDeduction;
                }
            };

            // ---- TRUST CHECKS (Tampering / Bots) ----

            // 1. WebDriver Check
            if (navigator.webdriver) {
                addAnomaly('webdriver', 'WebDriver signal detected', 'danger', 'trust', 40);
            }

            // 2. Headless Checks
            if (window.outerWidth === 0 && window.outerHeight === 0) {
                addAnomaly('headless_dims', 'Zero window dimensions', 'danger', 'trust', 30);
            }
            if (!('chrome' in window) && navigator.userAgent.includes('Chrome/')) {
                addAnomaly('missing_chrome', 'Missing window.chrome in Chrome', 'suspicious', 'trust', 20);
            }

            // 3. PhantomJS
            if (('callPhantom' in window) || ('_phantom' in window)) {
                addAnomaly('phantomjs', 'PhantomJS runtime', 'danger', 'trust', 50);
            }
            if ('domAutomation' in window || 'domAutomationController' in window) {
                addAnomaly('dom_automation', 'DOM Automation object', 'danger', 'trust', 40);
            }

            // 4. Overrides
            const uaDescriptor = Object.getOwnPropertyDescriptor(navigator, 'userAgent');
            if (uaDescriptor && (uaDescriptor.value !== undefined || uaDescriptor.get !== undefined)) {
                addAnomaly('ua_override', 'UserAgent tampered', 'danger', 'trust', 30);
            }

            const platformDescriptor = Object.getOwnPropertyDescriptor(navigator, 'platform');
            if (platformDescriptor && (platformDescriptor.value !== undefined || platformDescriptor.get !== undefined)) {
                addAnomaly('platform_override', 'Platform tampered', 'danger', 'trust', 30);
            }

            // 5. Engine stack mismatches
            try {
                // @ts-ignore
                null.test();
            } catch (e: any) {
                if (e.stack) {
                    const stackString = e.stack.toString();
                    if (navigator.userAgent.includes('Chrome') && stackString.includes('@')) {
                        addAnomaly('engine_mismatch', 'JS Engine error stack mismatch', 'danger', 'trust', 30);
                    }
                }
            }

            // ---- NORMALCY CHECKS (Configuration Consistency) ----

            const ua = navigator.userAgent || '';
            const platform = navigator.platform || '';

            // OS Mismatches
            if (ua.includes('Windows') && !platform.includes('Win')) {
                addAnomaly('os_mismatch', 'Windows UA but non-Win platform', 'danger', 'normalcy', 30);
            }
            if (ua.includes('Mac OS') && !platform.includes('Mac')) {
                addAnomaly('os_mismatch', 'Mac UA but non-Mac platform', 'danger', 'normalcy', 30);
            }
            if (ua.includes('Linux') && !platform.includes('Linux') && !platform.includes('Android')) {
                addAnomaly('os_mismatch', 'Linux UA but non-Linux platform', 'danger', 'normalcy', 30);
            }

            // Arch Mismatches (e.g., iPhone returning Linux x86_64 or Desktop returning arm)
            const isUAaarch64 = ua.includes('aarch64') || ua.includes('arm');
            const isPlatformx86 = platform.includes('x86') || platform.includes('i686');
            if (isUAaarch64 && isPlatformx86) {
                addAnomaly('arch_mismatch', 'ARM UA with x86 Platform', 'danger', 'normalcy', 30);
            }

            // Mobile vs Desktop
            const isMobileUA = /Mobi|Android|iPhone|iPad/i.test(ua);
            const isDesktopPlatform = /Win32|Win64|MacIntel|Linux x86_64/.test(platform);
            if (isMobileUA && isDesktopPlatform) {
                addAnomaly('mobile_desktop_mismatch', 'Mobile UA on Desktop Platform', 'danger', 'normalcy', 25);
            }

            // High core counts on mobile (Often unlikely for certain architectures but this is a soft check)
            if (isMobileUA && navigator.hardwareConcurrency > 10) {
                addAnomaly('hardware_anomaly', 'Unusually high cores for mobile', 'suspicious', 'normalcy', 15);
            }

            // Touch support contradictions
            if (isMobileUA && navigator.maxTouchPoints === 0) {
                addAnomaly('touch_mismatch', 'Mobile UA without touch points', 'suspicious', 'normalcy', 20);
            }

            // Missing Languages
            if (!navigator.languages || navigator.languages.length === 0) {
                addAnomaly('no_languages', 'No languages specified', 'suspicious', 'normalcy', 15);
            }

            // Wait for permissions
            try {
                if (navigator.permissions && navigator.permissions.query) {
                    const notifPerm = await navigator.permissions.query({ name: 'notifications' });
                    if (Notification.permission === 'denied' && notifPerm.state === 'prompt') {
                        addAnomaly('permission_mismatch', 'Permissions API contradicts Notification API', 'danger', 'trust', 25);
                    }
                }
            } catch (e) {
                // Ignore if query fails
            }

            trustScore = Math.max(0, trustScore);
            normalcyScore = Math.max(0, normalcyScore);

            const trustLevel: AnomalyLevel = trustScore < 50 ? 'danger' : (trustScore < 90 ? 'suspicious' : 'safe');
            const normalcyLevel: AnomalyLevel = normalcyScore < 50 ? 'danger' : (normalcyScore < 85 ? 'suspicious' : 'safe');

            setAssessment({
                isTrusted: trustScore >= 90,
                trustScore,
                normalcyScore,
                trustLevel,
                normalcyLevel,
                anomalies,
                isLoading: false
            });
        };

        analyze();
    }, []);

    return assessment;
};

import { useCallback, useMemo } from 'react';
import { formatNumber, formatPercent, formatList, formatBytes, formatSpeed, formatHertz } from '../utils/formatters';

export const useFormatter = (locale: string) => {

  // Advanced: Intl.DisplayNames
  // Returns the name of a language code (e.g. 'zh-CN' -> 'Chinese (Simplified)') in the CURRENT locale
  const formatLanguageName = useCallback((code: string) => {
    try {
      // @ts-ignore - TS might not know about DisplayNames in older libs
      if (typeof Intl.DisplayNames !== 'undefined') {
        // @ts-ignore
        return new Intl.DisplayNames([locale], { type: 'language' }).of(code) || code;
      }
      return code;
    } catch (e) { return code; }
  }, [locale]);

  // Returns the name of a region code (e.g. 'US' -> 'United States') in the CURRENT locale
  const formatRegionName = useCallback((code: string) => {
    try {
      // @ts-ignore
      if (typeof Intl.DisplayNames !== 'undefined') {
        // @ts-ignore
        return new Intl.DisplayNames([locale], { type: 'region' }).of(code) || code;
      }
      return code;
    } catch (e) { return code; }
  }, [locale]);

  // Returns the Native name of a language (e.g. 'ja' -> '日本語' even if current locale is en)
  // Useful for language switchers
  const formatNativeLanguageName = useCallback((code: string) => {
    try {
      // @ts-ignore
      if (typeof Intl.DisplayNames !== 'undefined') {
        // @ts-ignore
        return new Intl.DisplayNames([code], { type: 'language' }).of(code) || code;
      }
      return code;
    } catch (e) { return code; }
  }, []);

  // Relative Time (e.g., "5 minutes ago")
  const formatRelativeTime = useCallback((value: number, unit: Intl.RelativeTimeFormatUnit, options?: Intl.RelativeTimeFormatOptions) => {
    try {
      if (typeof Intl.RelativeTimeFormat !== 'undefined') {
        return new Intl.RelativeTimeFormat(locale, options).format(value, unit);
      }
      return `${value} ${unit}`;
    } catch (e) { return `${value} ${unit}`; }
  }, [locale]);

  // Bind existing utils to the hook's locale
  // useMemo ensures these functions are stable references unless locale changes
  const num = useCallback((n: number, maxD?: number, minD?: number) => formatNumber(n, maxD, minD, locale), [locale]);
  const pct = useCallback((n: number, maxD?: number) => formatPercent(n, maxD, locale), [locale]);
  const list = useCallback((l: string[], type?: 'conjunction' | 'disjunction' | 'unit') => formatList(l, type, locale), [locale]);
  const bytes = useCallback((b: number) => formatBytes(b, locale), [locale]);

  return {
    locale,
    formatLanguageName,
    formatRegionName,
    formatNativeLanguageName,
    formatRelativeTime,
    number: num,
    percent: pct,
    list: list,
    bytes: bytes,
    speed: (s: number) => formatSpeed(s, locale),
    hertz: (h: number) => formatHertz(h, locale)
  };
};

