function generateData(size: number) {
    const arr = new Uint8Array(size);
    for(let i=0; i<size; i+=1024) arr[i] = i % 255;
    return new Blob([arr]);
}

function openDB(): Promise<IDBDatabase> {
    return new Promise((resolve, reject) => {
        const req = indexedDB.open('BrowserScopeBench', 1);
        req.onupgradeneeded = (e: any) => {
            const db = e.target.result;
            if (!db.objectStoreNames.contains('store')) {
                db.createObjectStore('store', { keyPath: ['id', 'chunk'] });
            }
        };
        req.onsuccess = (e: any) => resolve(e.target.result);
        req.onerror = () => reject(req.error);
    });
}

async function cleanup(filename: string, tgt: string) {
    try {
        if (tgt === 'idb') {
            await new Promise<void>((resolve) => {
                const req = indexedDB.deleteDatabase('BrowserScopeBench');
                req.onsuccess = () => resolve();
                req.onerror = () => resolve(); 
                req.onblocked = () => resolve(); 
            });
        } else if (tgt === 'cache') {
            if (typeof caches !== 'undefined') {
                await caches.delete('bench-cache');
            }
        } else if (tgt === 'opfs') {
            if (navigator.storage && navigator.storage.getDirectory) {
                const root = await navigator.storage.getDirectory();
                try {
                    // Modern way to iterate over directory
                    // @ts-ignore
                    for await (const [name, handle] of root) {
                        if (name.startsWith('bench_')) {
                            await root.removeEntry(name, { recursive: true }).catch(() => {});
                        }
                    }
                } catch(e) {
                    // Fallback if async iterator fails
                    try {
                        await root.removeEntry(filename).catch(()=> {});
                    } catch(err) {}
                }
            }
        }
    } catch (e) {
        // Ignore overall error
        console.error("Cleanup error:", e);
    }
}

let isStopping = false;

self.onmessage = async function(e: MessageEvent) {
    if (e.data.type === 'stop') {
        isStopping = true;
        return;
    }
    isStopping = false;
    const { target, sizeMB, chunkSizeKB, origin } = e.data;
    const totalBytes = sizeMB * 1024 * 1024;
    const CHUNK_SIZE = chunkSizeKB * 1024;
    const chunks = Math.ceil(totalBytes / CHUNK_SIZE);
    const filename = 'bench_' + Date.now() + '.bin';

    const writeLatencies: number[] = [];
    const readLatencies: number[] = [];

    try {
        // --- WRITE PHASE ---
        const startWrite = performance.now();

        let writeDb: IDBDatabase | null = null;
        if (target === 'idb') {
            writeDb = await openDB();
            for(let i=0; i<chunks; i++) {
                if (isStopping) break;
                const chunk = generateData(CHUNK_SIZE); 
                const txStart = performance.now();
                const tx = writeDb.transaction('store', 'readwrite');
                const store = tx.objectStore('store');

                await new Promise<void>((resolve, reject) => {
                    const req = store.put({ id: filename, chunk: i, data: chunk });
                    req.onsuccess = () => resolve();
                    req.onerror = () => reject(req.error);
                });
                writeLatencies.push(performance.now() - txStart);

                const now = performance.now();
                const elapsed = (now - startWrite) / 1000;
                const written = (i + 1) * CHUNK_SIZE;
                self.postMessage({
                    type: 'progress',
                    phase: 'writing',
                    speed: (written / 1024 / 1024) / elapsed,
                    progress: Math.floor(((i + 1) / chunks) * 50)
                });
            }
            writeDb.close();
        } 
        else if (target === 'cache') {
            if (typeof caches === 'undefined') {
                throw new Error("Cache API not supported inside worker");
            }
            const cache = await caches.open('bench-cache');
            const data = generateData(totalBytes); 
            const response = new Response(data);

            // To avoid blob scheme issues, always use absolute URL with http(s)
            const cacheUrl = new URL(filename, origin || self.location.origin).toString();

            const txStart = performance.now();
            await cache.put(cacheUrl, response);
            writeLatencies.push(performance.now() - txStart);

            const now = performance.now();
            const elapsed = (now - startWrite) / 1000;
            self.postMessage({
                type: 'progress',
                phase: 'writing',
                speed: (totalBytes / 1024 / 1024) / elapsed,
                progress: 50
            });
        } 
        else if (target === 'opfs') {
            if (!navigator.storage || !navigator.storage.getDirectory) {
                throw new Error("OPFS is not supported inside worker context");
            }
            const root = await navigator.storage.getDirectory();
            const handle = await root.getFileHandle(filename, { create: true });

            let writable: any;
            let isSync = false;
            if ((handle as any).createSyncAccessHandle) {
                try {
                    writable = await (handle as any).createSyncAccessHandle();
                    isSync = true;
                } catch(e) {
                    writable = await handle.createWritable();
                }
            } else {
                writable = await handle.createWritable();
            }

            let offset = 0;
            for(let i=0; i<chunks; i++) {
                if (isStopping) break;
                const chunk = generateData(CHUNK_SIZE);
                const arrayBuffer = await chunk.arrayBuffer();

                const txStart = performance.now();
                if (isSync) {
                    writable.write(new Uint8Array(arrayBuffer), { at: offset });
                    offset += arrayBuffer.byteLength;
                } else {
                    await writable.write(chunk);
                }
                writeLatencies.push(performance.now() - txStart);

                const now = performance.now();
                const elapsed = (now - startWrite) / 1000;
                const written = (i + 1) * CHUNK_SIZE;

                self.postMessage({
                    type: 'progress',
                    phase: 'writing',
                    speed: (written / 1024 / 1024) / elapsed,
                    progress: Math.floor(((i + 1) / chunks) * 50)
                });
            }
            if (isSync) {
                writable.flush();
                writable.close();
            } else {
                await writable.close();
            }
        }

        if (isStopping) {
            await cleanup(filename, target);
            self.postMessage({ type: 'stopped' });
            return;
        }

        const endWrite = performance.now();
        const writeDuration = endWrite - startWrite;
        const writeSpeed = (totalBytes / 1024 / 1024) / (writeDuration / 1000);

        const avgWriteLat = writeLatencies.length > 0 ? writeLatencies.reduce((a,b)=>a+b,0)/writeLatencies.length : 0;
        const peakWriteLat = writeLatencies.length > 0 ? Math.max(...writeLatencies) : 0;

        self.postMessage({
            type: 'result',
            op: 'Write',
            throughput: writeSpeed,
            avgLatency: avgWriteLat,
            peakLatency: peakWriteLat,
            duration: writeDuration
        });

        // --- READ PHASE ---
        const startRead = performance.now();

        let readDb: IDBDatabase | null = null;
        if (target === 'idb') {
            readDb = await openDB();
            for(let i=0; i<chunks; i++) {
                if (isStopping) break;
                const txStart = performance.now();
                const tx = readDb.transaction('store', 'readonly');
                const store = tx.objectStore('store');

                await new Promise<void>((resolve, reject) => {
                    const req = store.get([filename, i]);
                    req.onsuccess = () => resolve();
                    req.onerror = () => reject(req.error);
                });
                readLatencies.push(performance.now() - txStart);

                const now = performance.now();
                const elapsed = (now - startRead) / 1000;
                const read = (i + 1) * CHUNK_SIZE;

                self.postMessage({
                    type: 'progress',
                    phase: 'reading',
                    speed: (read / 1024 / 1024) / elapsed,
                    progress: 50 + Math.floor(((i + 1) / chunks) * 50)
                });
            }
            readDb.close();
        }
        else if (target === 'cache') {
            const cacheUrl = new URL(filename, origin || self.location.origin).toString();
            const cache = await caches.open('bench-cache');
            const txStart = performance.now();
            const res = await cache.match(cacheUrl);
            if (res) {
                await res.blob();
            }
            readLatencies.push(performance.now() - txStart);

            const now = performance.now();
            const elapsed = (now - startRead) / 1000;
            self.postMessage({
                type: 'progress',
                phase: 'reading',
                speed: (totalBytes / 1024 / 1024) / elapsed,
                progress: 100
            });
        }
        else if (target === 'opfs') {
            const root = await navigator.storage.getDirectory();
            const handle = await root.getFileHandle(filename);

            if ((handle as any).createSyncAccessHandle) {
                const accessHandle = await (handle as any).createSyncAccessHandle();
                const fileLength = accessHandle.getSize();
                const buffer = new Uint8Array(CHUNK_SIZE);
                let readBytes = 0;

                while (readBytes < fileLength) {
                    if (isStopping) break;
                    const chunkStart = performance.now();
                    const n = accessHandle.read(buffer, { at: readBytes });
                    if (n === 0) break;
                    readLatencies.push(performance.now() - chunkStart);
                    readBytes += n;

                    const now = performance.now();
                    const elapsed = (now - startRead) / 1000;

                    self.postMessage({
                        type: 'progress',
                        phase: 'reading',
                        speed: (readBytes / 1024 / 1024) / elapsed,
                        progress: 50 + Math.floor((readBytes / fileLength) * 50)
                    });
                }
                accessHandle.close();
            } else {
                const file = await handle.getFile();
                const reader = file.stream().getReader();
                let readBytes = 0;
                while(true) {
                    if (isStopping) break;
                    const chunkStart = performance.now();
                    const { done, value } = await reader.read();
                    if (done) break;
                    readLatencies.push(performance.now() - chunkStart);
                    readBytes += (value as any).length;

                    const now = performance.now();
                    const elapsed = (now - startRead) / 1000;

                    self.postMessage({
                        type: 'progress',
                        phase: 'reading',
                        speed: (readBytes / 1024 / 1024) / elapsed,
                        progress: 50 + Math.floor((readBytes / totalBytes) * 50)
                    });
                }
            }
        }

        if (isStopping) {
            await cleanup(filename, target);
            self.postMessage({ type: 'stopped' });
            return;
        }

        const endRead = performance.now();
        const readDuration = endRead - startRead;
        const readSpeed = (totalBytes / 1024 / 1024) / (readDuration / 1000);

        const avgReadLat = readLatencies.length > 0 ? readLatencies.reduce((a,b)=>a+b,0)/readLatencies.length : 0;
        const peakReadLat = readLatencies.length > 0 ? Math.max(...readLatencies) : 0;

        self.postMessage({
            type: 'result',
            op: 'Read',
            throughput: readSpeed,
            avgLatency: avgReadLat,
            peakLatency: peakReadLat,
            duration: readDuration
        });

        await cleanup(filename, target);
        self.postMessage({ type: 'done' });

    } catch (err: any) {
        await cleanup(filename, target);
        self.postMessage({ type: 'error', message: err.message || "Unknown error inside Web Worker" });
    }
};

// A centralized place for Intl formatters to ensure performance (reuse instances) and consistency

// Fix: Add type definitions for Intl.ListFormat if they are missing
declare global {
  namespace Intl {
    interface ListFormatOptions {
      localeMatcher?: 'lookup' | 'best fit';
      type?: 'conjunction' | 'disjunction' | 'unit';
      style?: 'long' | 'short' | 'narrow';
    }
  }
}

// Cache formatters to avoid re-instantiating overhead
// Key now includes locale to support dynamic switching
const numberFormatters = new Map<string, Intl.NumberFormat>();
const listFormatters = new Map<string, Intl.ListFormat>();

const getNumberFormatter = (locale: string | undefined, options?: Intl.NumberFormatOptions) => {
    const key = `${locale || 'default'}-${JSON.stringify(options)}`;
    if (!numberFormatters.has(key)) {
        numberFormatters.set(key, new Intl.NumberFormat(locale, options));
    }
    return numberFormatters.get(key)!;
};

const getListFormatter = (locale: string | undefined, options?: Intl.ListFormatOptions) => {
    // Only available in modern browsers
    if (typeof Intl.ListFormat === 'undefined') return null;

    const key = `${locale || 'default'}-${JSON.stringify(options)}`;
    if (!listFormatters.has(key)) {
        listFormatters.set(key, new Intl.ListFormat(locale, options));
    }
    return listFormatters.get(key)!;
};

/**
 * Formats bytes into localized string with unit (e.g., "10.5 GB", "500 MB")
 * Uses Intl.NumberFormat for unit display
 */
export const formatBytes = (bytes: number, locale?: string): string => {
  if (bytes === 0) return '0 B';
  if (isNaN(bytes)) return 'Unknown';

  const k = 1024;
  const i = Math.floor(Math.log(bytes) / Math.log(k));
  const sizes = ['byte', 'kilobyte', 'megabyte', 'gigabyte', 'terabyte', 'petabyte'];

  // Guard against very large numbers out of range
  const unitIndex = Math.min(i, sizes.length - 1);
  const value = bytes / Math.pow(k, unitIndex);

  try {
      return getNumberFormatter(locale, {
        style: 'unit',
        unit: sizes[unitIndex],
        unitDisplay: 'short',
        maximumFractionDigits: 2
      }).format(value);
  } catch (e) {
      // Fallback for older browsers if unit is not supported
      const suffixes = ['B', 'KB', 'MB', 'GB', 'TB', 'PB'];
      return `${value.toFixed(2)} ${suffixes[unitIndex]}`;
  }
};

/**
 * Formats network speed (Mbps/Gbps)
 */
export const formatSpeed = (mbps: number, locale?: string): string => {
    if (isNaN(mbps) || mbps === 0) return 'Unknown';

    try {
        return getNumberFormatter(locale, {
            style: 'unit',
            unit: 'megabit-per-second',
            unitDisplay: 'short',
            maximumFractionDigits: 1
        }).format(mbps);
    } catch (e) {
        return `${mbps.toFixed(1)} Mbps`;
    }
};

/**
 * Formats simple frequency (Hz)
 */
export const formatHertz = (hz: number, locale?: string): string => {
    if (isNaN(hz)) return 'Unknown';
    try {
        return getNumberFormatter(locale, {
            style: 'unit',
            unit: 'hertz',
            unitDisplay: 'short',
            maximumFractionDigits: 0
        }).format(hz);
    } catch (e) {
        return `${hz} Hz`;
    }
};

/**
 * Formats a generic number (integers or floats) with locale-aware separators.
 * e.g., 10000 -> "10,000" (en) or "10 000" (fr)
 */
export const formatNumber = (num: number, maxDecimals: number = 0, minDecimals: number = 0, locale?: string): string => {
    if (isNaN(num)) return '0';
    return getNumberFormatter(locale, {
        minimumFractionDigits: minDecimals,
        maximumFractionDigits: maxDecimals
    }).format(num);
};

/**
 * Formats a ratio (0 to 1) as a percentage string.
 * e.g., 0.85 -> "85%"
 */
export const formatPercent = (ratio: number, maxDecimals: number = 0, locale?: string): string => {
    if (isNaN(ratio)) return '0%';
    return getNumberFormatter(locale, {
        style: 'percent',
        maximumFractionDigits: maxDecimals
    }).format(ratio);
};

/**
 * Formats a list of strings into a localized list string.
 * e.g., ['A', 'B', 'C'] -> "A, B, and C" (en) or "A、B和C" (zh)
 */
export const formatList = (list: string[], type: 'conjunction' | 'disjunction' | 'unit' = 'conjunction', locale?: string): string => {
    if (!list || list.length === 0) return '';

    const formatter = getListFormatter(locale, { style: 'long', type });
    if (formatter) {
        return formatter.format(list);
    }

    // Fallback
    return list.join(', ');
};

/**
 * Generates a timestamp string for filenames (YYYY-MM-DD-HH-MM)
 * Uses Intl to ensure parts are correct regardless of timezone
 */
export const generateFilenameTimestamp = (): string => {
    const now = new Date();
    // We use 'en-CA' because it formats as YYYY-MM-DD (ISO-8601-like) which is sortable
    // hour12: false guarantees 24h format
    const formatter = new Intl.DateTimeFormat('en-CA', {
        year: 'numeric',
        month: '2-digit',
        day: '2-digit',
        hour: '2-digit',
        minute: '2-digit',
        hour12: false
    });

    // Format parts and replace standard separators with hyphens for filename safety
    const parts = formatter.formatToParts(now);
    const getPart = (type: string) => parts.find(p => p.type === type)?.value || '00';

    return `${getPart('year')}-${getPart('month')}-${getPart('day')}-${getPart('hour')}-${getPart('minute')}`;
};

export async function loadEruda(store: any) {
  if ((window as any).eruda) {
    try {
      (window as any).eruda.show();
    } catch (e) {}
    return;
  }
  try {
    let container = document.getElementById("eruda-container");
    if (!container) {
      container = document.createElement("div");
      container.id = "eruda-container";
      container.style.overscrollBehavior = "none";
      document.body.appendChild(container);
    }

    const eruda = (await import("eruda")).default;
    eruda.init({
      container: container,
      useShadowDom: true,
    });
    (window as any).eruda = eruda;

    const erudaTiming = (await import("eruda-timing")).default;
    eruda.add(erudaTiming);

    try { const erudaDom = (await import("eruda-dom")).default; eruda.add(erudaDom); } catch (e) {}
    try { const erudaCode = (await import("eruda-code")).default; eruda.add(erudaCode); } catch (e) {}
    try { const erudaMonitor = (await import("eruda-monitor")).default; eruda.add(erudaMonitor); } catch (e) {}
    try { const erudaFeatures = (await import("eruda-features")).default; eruda.add(erudaFeatures); } catch (e) {}
    try { const erudaFps = (await import("eruda-fps")).default; eruda.add(erudaFps); } catch (e) {}

    try { eruda.show(store.erudaDefaultTab); } catch (e) {}

    const snippets = eruda.get("snippets");
    if (snippets) {
      if (store.erudaSnippets.clear_local) {
        snippets.add(
          "Clear LocalStorage",
          function () {
            localStorage.clear();
            alert("LocalStorage cleared");
          },
          "Clears all data from localStorage",
        );
      }
      if (store.erudaSnippets.clear_session) {
        snippets.add(
          "Clear SessionStorage",
          function () {
            sessionStorage.clear();
            alert("SessionStorage cleared");
          },
          "Clears all data from sessionStorage",
        );
      }
      if (store.erudaSnippets.show_cookies) {
        snippets.add(
          "Show Cookies",
          function () {
            alert(document.cookie || "No cookies found");
          },
          "Alerts all current document cookies",
        );
      }
      if (store.erudaSnippets.toggle_blur) {
        snippets.add(
          "Disable Body Blur",
          function () {
            document.body.classList.toggle("no-blur");
          },
          "Toggles body blur",
        );
      }
      if (store.erudaSnippets.toggle_editable) {
        snippets.add(
          "Toggle Editable Page",
          function () {
            document.body.contentEditable =
              document.body.contentEditable === "true" ? "false" : "true";
          },
          "Toggles content editable mode for the entire page",
        );
      }
    }

    container.addEventListener("wheel", (e) => e.stopPropagation(), {
      passive: false,
    });
    container.addEventListener("touchstart", (e) => e.stopPropagation(), {
      passive: false,
    });
    container.addEventListener("touchmove", (e) => e.stopPropagation(), {
      passive: false,
    });
    container.addEventListener("touchend", (e) => e.stopPropagation(), {
      passive: false,
    });

    if (container.shadowRoot) {
      const style = document.createElement("style");
      style.textContent = `
        * { overscroll-behavior: none !important; }
      `;
      container.shadowRoot.appendChild(style);
    }

    const observer = new MutationObserver((mutations) => {
      mutations.forEach((mutation) => {
        if (mutation.attributeName === "class") {
          const isCurrentlyDark =
            document.documentElement.classList.contains("dark");
          if (
            (window as any).eruda &&
            typeof (window as any).eruda.position === "function"
          ) {
            try {
              (window as any).eruda._devTools._theme = isCurrentlyDark
                ? "Dark"
                : "Light";
              (window as any).eruda._devTools.emit(
                "themeChange",
                isCurrentlyDark ? "Dark" : "Light",
              );
            } catch (e) {}
          }
        }
      });
    });
    observer.observe(document.documentElement, { attributes: true });
  } catch (e) {}
}

export function unloadEruda() {
  if ((window as any).eruda) {
    try {
      (window as any).eruda.destroy();
    } catch (e) {}
    (window as any).eruda = undefined;
    const erudaNode = document.getElementById("eruda-container");
    if (erudaNode) {
      erudaNode.remove();
    }
    const el = document.querySelector('div[id="eruda"]');
    if (el) el.remove();
  }
}

import { loadVConsole } from "./vconsole";
import { loadEruda } from "./eruda";

export function setupInterceptors(loggerStore: any) {
  if (typeof window === "undefined") return;

  if (loggerStore.activeConsole === "vconsole") {
    loadVConsole(loggerStore);
  } else if (loggerStore.activeConsole === "eruda") {
    loadEruda(loggerStore);
  }

  const originalLog = console.log;
  const originalError = console.error;
  const originalWarn = console.warn;
  const originalInfo = console.info;

  const serializeArgs = (args: any[]) =>
    args
      .map((a) => {
        try {
          return typeof a === "object" ? JSON.stringify(a) : String(a);
        } catch (e) {
          return String(a);
        }
      })
      .join(" ");

  console.log = function (...args) {
    if (loggerStore.isLoggingEnabled)
      loggerStore.addConsole("output", serializeArgs(args));
    originalLog.apply(console, args);
  };
  console.error = function (...args) {
    if (loggerStore.isLoggingEnabled)
      loggerStore.addConsole("error", serializeArgs(args));
    originalError.apply(console, args);
  };
  console.warn = function (...args) {
    if (loggerStore.isLoggingEnabled)
      loggerStore.addConsole("warn", serializeArgs(args));
    originalWarn.apply(console, args);
  };
  console.info = function (...args) {
    if (loggerStore.isLoggingEnabled)
      loggerStore.addConsole("info", serializeArgs(args));
    originalInfo.apply(console, args);
  };

  const handleResize = () =>
    loggerStore.addLog("resize", `${window.innerWidth}x${window.innerHeight}`);
  const handleVisibility = () =>
    loggerStore.addLog("visibilitychange", document.visibilityState);
  const handleOnline = () => loggerStore.addLog("network", "online");
  const handleOffline = () => loggerStore.addLog("network", "offline");
  const handleFocus = () => loggerStore.addLog("window", "focus");
  const handleBlur = () => loggerStore.addLog("window", "blur");
  window.addEventListener("resize", handleResize);
  document.addEventListener("visibilitychange", handleVisibility);
  window.addEventListener("online", handleOnline);
  window.addEventListener("offline", handleOffline);
  window.addEventListener("focus", handleFocus);
  window.addEventListener("blur", handleBlur);

  window.addEventListener("error", (e) => {
    loggerStore.addConsole(
      "error",
      `[Uncaught Error] ${e.message}\n${e.error?.stack || ""}`,
    );
  });
  window.addEventListener("unhandledrejection", (e) => {
    loggerStore.addConsole(
      "error",
      `[Unhandled Promise Rejection] ${e.reason}`,
    );
  });
}

export async function loadVConsole(store: any) {
  const win = window as any;
  if (win.vConsole) {
    try {
      win.vConsole.show();
    } catch (e) {}
    return;
  }
  try {
    if (!Object.getOwnPropertyDescriptor(window, "fetch")) {
      const originalFetch = window.fetch;
      Object.defineProperty(window, "fetch", {
        configurable: true,
        enumerable: true,
        writable: true,
        value: originalFetch,
      });
    }
    const VConsole = (await import("vconsole")).default;
    const isDark = document.documentElement.classList.contains("dark");
    win.vConsole = new (VConsole as any)({
      theme: isDark ? "dark" : "light",
    });
    try {
      if (store.vconsoleDefaultTab && store.vconsoleDefaultTab !== "default") {
        setTimeout(() => win.vConsole.showPlugin(store.vconsoleDefaultTab), 100);
      }
    } catch (e) {}

    const observer = new MutationObserver((mutations) => {
      mutations.forEach((mutation) => {
        if (mutation.attributeName === "class") {
          const isCurrentlyDark =
            document.documentElement.classList.contains("dark");
          if (win.vConsole && typeof win.vConsole.setOption === "function") {
            win.vConsole.setOption(
              "theme",
              isCurrentlyDark ? "dark" : "light",
            );
          }
        }
      });
    });
    observer.observe(document.documentElement, { attributes: true });
  } catch (e) {}
}

export function unloadVConsole() {
  const win = window as any;
  if (win.vConsole) {
    try {
      win.vConsole.destroy();
    } catch (e) {}
    win.vConsole = undefined;
    const vcNode = document.getElementById("__vconsole");
    if (vcNode) {
      vcNode.remove();
    }
  }
}

import { useState, useEffect } from "react";
import { ConsoleEntry } from "./logger/types";
import { loadEruda, unloadEruda } from "./logger/eruda";
import { loadVConsole, unloadVConsole } from "./logger/vconsole";
import { setupInterceptors } from "./logger/interceptors";

export type { ConsoleEntry };

class LoggerStore {
  public logs: string[] = [];
  public consoleHistory: ConsoleEntry[] = [];
  public isLoggingEnabled: boolean =
    localStorage.getItem("developer_logging_enabled") !== "false";
  public activeConsole: "none" | "vconsole" | "eruda" =
    (localStorage.getItem("developer_active_console") as any) || "none";
  public defaultConsole: "vconsole" | "eruda" =
    (localStorage.getItem("developer_default_console") as any) || "vconsole";
  public erudaDefaultTab: string =
    localStorage.getItem("developer_eruda_default_tab") || "console";
  public vconsoleDefaultTab: string =
    localStorage.getItem("developer_vconsole_default_tab") || "default";
  public erudaSnippets: Record<string, boolean> = (() => {
    try {
      const stored = localStorage.getItem("developer_eruda_snippets");
      return stored ? JSON.parse(stored) : { clear_local: true, clear_session: true, show_cookies: true, toggle_blur: true, toggle_editable: true };
    } catch {
      return { clear_local: true, clear_session: true, show_cookies: true, toggle_blur: true, toggle_editable: true };
    }
  })();

  private logListeners: Set<(logs: string[]) => void> = new Set();
  private consoleListeners: Set<(history: ConsoleEntry[]) => void> = new Set();
  private settingsListeners: Set<() => void> = new Set();

  constructor() {
    try {
      const savedLogs = sessionStorage.getItem("dev_logs");
      if (savedLogs) this.logs = JSON.parse(savedLogs);

      const savedConsole = sessionStorage.getItem("dev_console");
      if (savedConsole) this.consoleHistory = JSON.parse(savedConsole);
    } catch (e) {}
  }

  private persistLogs() {
    try {
      sessionStorage.setItem("dev_logs", JSON.stringify(this.logs));
    } catch (e) {}
  }

  private persistConsole() {
    try {
      sessionStorage.setItem(
        "dev_console",
        JSON.stringify(this.consoleHistory),
      );
    } catch (e) {}
  }

  addLog(type: string, detail: string) {
    if (!this.isLoggingEnabled) return;
    const time = new Date().toLocaleTimeString("en-US", {
      hour12: false,
      hour: "2-digit",
      minute: "2-digit",
      second: "2-digit",
      fractionalSecondDigits: 3,
    } as any);
    this.logs = [`[${time}] ${type}: ${detail}`, ...this.logs].slice(0, 500);
    this.persistLogs();
    this.notifyLogs();
  }

  clearLogs() {
    this.logs = [];
    this.persistLogs();
    this.notifyLogs();
  }

  addConsole(type: ConsoleEntry["type"] | "warn" | "info", content: string) {
    if (!this.isLoggingEnabled && type !== "input") return;

    let normalizedType: ConsoleEntry["type"] = "output";
    if (type === "error") normalizedType = "error";
    else if (type === "input") normalizedType = "input";

    this.consoleHistory = [
      ...this.consoleHistory,
      {
        id: Math.random().toString(36).substr(2, 9),
        type: normalizedType,
        content,
        timestamp: Date.now(),
      },
    ];
    if (this.consoleHistory.length > 500) {
      this.consoleHistory.shift();
    }
    this.persistConsole();
    this.notifyConsole();
  }

  clearConsole() {
    this.consoleHistory = [];
    this.persistConsole();
    this.notifyConsole();
  }

  setLoggingEnabled(enabled: boolean) {
    this.isLoggingEnabled = enabled;
    localStorage.setItem("developer_logging_enabled", String(enabled));
    this.notifySettings();
  }

  setErudaSnippet(key: string, enabled: boolean) {
    this.erudaSnippets = { ...this.erudaSnippets, [key]: enabled };
    localStorage.setItem("developer_eruda_snippets", JSON.stringify(this.erudaSnippets));
    if (this.activeConsole === "eruda") {
      unloadEruda();
      loadEruda(this);
    }
    this.notifySettings();
  }

  setErudaDefaultTab(tab: string) {
    this.erudaDefaultTab = tab;
    localStorage.setItem("developer_eruda_default_tab", tab);
    if (this.activeConsole === "eruda" && (window as any).eruda) {
      try {
        (window as any).eruda.show(tab);
      } catch (e) {}
    }
    this.notifySettings();
  }

  setVconsoleDefaultTab(tab: string) {
    this.vconsoleDefaultTab = tab;
    localStorage.setItem("developer_vconsole_default_tab", tab);
    if (this.activeConsole === "vconsole" && (window as any).vConsole) {
      try {
        (window as any).vConsole.showPlugin(tab);
      } catch (e) {}
    }
    this.notifySettings();
  }

  setActiveConsole(consoleType: "none" | "vconsole" | "eruda") {
    const previousConsole = this.activeConsole;
    this.activeConsole = consoleType;
    localStorage.setItem("developer_active_console", consoleType);

    if (previousConsole === "vconsole" && consoleType !== "vconsole") {
      unloadVConsole();
    } else if (previousConsole === "eruda" && consoleType !== "eruda") {
      unloadEruda();
    }

    if (consoleType === "vconsole") {
      loadVConsole(this);
    } else if (consoleType === "eruda") {
      loadEruda(this);
    }

    this.notifySettings();
  }

  setDefaultConsole(consoleType: "vconsole" | "eruda") {
    this.defaultConsole = consoleType;
    localStorage.setItem("developer_default_console", consoleType);

    if (this.activeConsole !== "none") {
      this.setActiveConsole(consoleType);
    } else {
      this.notifySettings();
    }
  }

  subscribeLogs(listener: (logs: string[]) => void) {
    this.logListeners.add(listener);
    return () => this.logListeners.delete(listener);
  }

  subscribeConsole(listener: (history: ConsoleEntry[]) => void) {
    this.consoleListeners.add(listener);
    return () => this.consoleListeners.delete(listener);
  }

  subscribeSettings(listener: () => void) {
    this.settingsListeners.add(listener);
    return () => this.settingsListeners.delete(listener);
  }

  private notifyLogs() {
    this.logListeners.forEach((fn) => fn(this.logs));
  }

  private notifyConsole() {
    this.consoleListeners.forEach((fn) => fn(this.consoleHistory));
  }

  private notifySettings() {
    this.settingsListeners.forEach((fn) => fn());
  }
}

export const loggerStore = new LoggerStore();

export function useLoggerStore() {
  const [logs, setLogs] = useState(loggerStore.logs);
  const [consoleHistory, setConsoleHistory] = useState(
    loggerStore.consoleHistory,
  );
  const [isLoggingEnabled, setIsLoggingEnabled] = useState(
    loggerStore.isLoggingEnabled,
  );
  const [activeConsole, setActiveConsole] = useState(loggerStore.activeConsole);
  const [defaultConsole, setDefaultConsole] = useState(
    loggerStore.defaultConsole,
  );
  const [erudaSnippets, setErudaSnippets] = useState(
    loggerStore.erudaSnippets,
  );
  const [erudaDefaultTab, setErudaDefaultTab] = useState(
    loggerStore.erudaDefaultTab,
  );
  const [vconsoleDefaultTab, setVconsoleDefaultTab] = useState(
    loggerStore.vconsoleDefaultTab,
  );

  useEffect(() => {
    const unsubs = [
      loggerStore.subscribeLogs(setLogs),
      loggerStore.subscribeConsole(setConsoleHistory),
      loggerStore.subscribeSettings(() => {
        setIsLoggingEnabled(loggerStore.isLoggingEnabled);
        setActiveConsole(loggerStore.activeConsole);
        setDefaultConsole(loggerStore.defaultConsole);
        setErudaSnippets(loggerStore.erudaSnippets);
        setErudaDefaultTab(loggerStore.erudaDefaultTab);
        setVconsoleDefaultTab(loggerStore.vconsoleDefaultTab);
      }),
    ];
    return () => unsubs.forEach((u) => u());
  }, []);

  return {
    logs,
    consoleHistory,
    isLoggingEnabled,
    activeConsole,
    defaultConsole,
    erudaSnippets,
    erudaDefaultTab,
    vconsoleDefaultTab,
    setActiveConsole: (type: "none" | "vconsole" | "eruda") =>
      loggerStore.setActiveConsole(type),
    setDefaultConsole: (type: "vconsole" | "eruda") =>
      loggerStore.setDefaultConsole(type),
    setErudaSnippet: (key: string, enabled: boolean) =>
      loggerStore.setErudaSnippet(key, enabled),
    setErudaDefaultTab: (tab: string) =>
      loggerStore.setErudaDefaultTab(tab),
    setVconsoleDefaultTab: (tab: string) =>
      loggerStore.setVconsoleDefaultTab(tab),
  };
}

setupInterceptors(loggerStore);
